bool Assets::Download(const std::string& url, std::function<void(int progress, size_t speed)> progress_callback)
{
    ESP_LOGI(TAG, "Starting download from %s", url.c_str());

    // Initialize HTTP client
    esp_http_client_config_t config = {
        .url = url.c_str(),
        .event_handler = nullptr,
        .user_data = this
    };

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == NULL) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    // Get content length
    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Get content length
    int content_length = esp_http_client_get_content_length(client);
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Invalid content length: %d", content_length);
        esp_http_client_cleanup(client);
        return false;
    }

    ESP_LOGI(TAG, "Content length: %d bytes", content_length);

    // Check if we have enough space in flash partition
    size_t partition_size = 0;
    esp_partition_t* partition = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_FAT, "assets");
    if (partition == NULL) {
        ESP_LOGE(TAG, "Failed to find assets partition");
        esp_http_client_cleanup(client);
        return false;
    }

    partition_size = partition->size;
    if ((size_t)content_length > partition_size) {
        ESP_LOGE(TAG, "Content too large for partition: %d > %zu", content_length, partition_size);
        esp_http_client_cleanup(client);
        return false;
    }

    // Erase the partition before writing
    ESP_LOGI(TAG, "Erasing partition...");
    err = esp_partition_erase_range(partition, 0, partition_size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Prepare to write data
    uint8_t* buffer = (uint8_t*)malloc(4096);
    if (buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        esp_http_client_cleanup(client);
        return false;
    }

    size_t total_written = 0;
    int last_progress = -1;
    uint64_t start_time = esp_timer_get_time();

    // Download and write data
    while (total_written < (size_t)content_length) {
        int read_len = esp_http_client_read(client, (char*)buffer, 4096);
        if (read_len < 0) {
            ESP_LOGE(TAG, "HTTP client read error: %s", esp_err_to_name(read_len));
            free(buffer);
            esp_http_client_cleanup(client);
            return false;
        }

        if (read_len == 0) {
            break; // End of stream
        }

        // Write to flash
        err = esp_partition_write(partition, total_written, buffer, read_len);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to flash: %s", esp_err_to_name(err));
            free(buffer);
            esp_http_client_cleanup(client);
            return false;
        }

        total_written += read_len;

        // Calculate progress
        int progress = (int)((total_written * 100.0) / content_length);
        if (progress != last_progress) {
            last_progress = progress;

            // Calculate speed
            uint64_t current_time = esp_timer_get_time();
            uint64_t elapsed_ms = (current_time - start_time) / 1000;
            size_t speed = 0;
            if (elapsed_ms > 0) {
                speed = (total_written * 1000) / elapsed_ms; // bytes per second
            }

            // Call progress callback
            if (progress_callback) {
                progress_callback(progress, speed);
            }

            ESP_LOGI(TAG, "Download progress: %d%% (%zu bytes)", progress, total_written);
        }
    }

    free(buffer);
    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    ESP_LOGI(TAG, "Download completed successfully");
    return true;
}

bool Assets::GetAssetData(const std::string &asset_name, void *&ptr, size_t &size)
{
    // Check if we have a valid assets table
    if (assets_table_ == nullptr) {
        ESP_LOGE(TAG, "Assets table not initialized");
        return false;
    }

    // Search for the asset in the table
    for (uint32_t i = 0; i < assets_table_length_; i++) {
        if (strcmp(assets_table_[i].asset_name, asset_name.c_str()) == 0) {
            // Asset found, get the data pointer
            uint32_t offset = assets_table_[i].asset_offset;
            uint32_t asset_size = assets_table_[i].asset_size;

            // Validate magic number (assuming first 4 bytes contain magic number)
            uint32_t *magic_ptr = (uint32_t *)((uint8_t *)assets_base_addr_ + offset);
            uint32_t magic_number = *magic_ptr;

            // Check if magic number is valid (example: 0x41535345 for "ASSE" in little endian)
            // This is just an example - actual magic number should match your asset format
            if (magic_number != 0x41535345) {  // "ASSE" in little endian
                ESP_LOGW(TAG, "Invalid magic number for asset %s", asset_name.c_str());
                return false;
            }

            // Set the output parameters
            ptr = (void *)((uint8_t *)assets_base_addr_ + offset + sizeof(uint32_t));  // Skip magic number
            size = asset_size - sizeof(uint32_t);  // Exclude magic number from size

            return true;
        }
    }

    // Asset not found
    ESP_LOGW(TAG, "Asset %s not found", asset_name.c_str());
    return false;
}

const char *DeviceStateMachine::GetStateName(DeviceState state)
{
    // Check if the state is within valid range
    if (state >= 0 && state < sizeof(STATE_STRINGS) / sizeof(STATE_STRINGS[0])) {
        return STATE_STRINGS[state];
    }

    // Return "unknown" for invalid states
    return STATE_STRINGS[0];
}

bool DeviceStateMachine::IsValidTransition(DeviceState from_state, DeviceState to_state) const
{
    // Self-transitions are generally allowed (staying in same state)
    if (from_state == to_state) {
        return true;
    }

    // Define valid state transitions
    switch (from_state) {
        case DEVICE_STATE_UNKNOWN:
            // Can transition to starting state
            return to_state == DEVICE_STATE_STARTING;

        case DEVICE_STATE_STARTING:
            // Can transition to wifi configuration or idle
            return (to_state == DEVICE_STATE_WIFI_CONFIGURING || 
                    to_state == DEVICE_STATE_IDLE);

        case DEVICE_STATE_WIFI_CONFIGURING:
            // Can transition to idle after configuration
            return to_state == DEVICE_STATE_IDLE;

        case DEVICE_STATE_IDLE:
            // Can transition to connecting, listening, speaking, or upgrading
            return (to_state == DEVICE_STATE_CONNECTING ||
                    to_state == DEVICE_STATE_LISTENING ||
                    to_state == DEVICE_STATE_SPEAKING ||
                    to_state == DEVICE_STATE_UPGRADING ||
                    to_state == DEVICE_STATE_AUDIO_TESTING ||
                    to_state == DEVICE_STATE_ACTIVATING);

        case DEVICE_STATE_CONNECTING:
            // Can transition to listening or fatal error
            return (to_state == DEVICE_STATE_LISTENING ||
                    to_state == DEVICE_STATE_FATAL_ERROR);

        case DEVICE_STATE_LISTENING:
            // Can transition to speaking or idle
            return (to_state == DEVICE_STATE_SPEAKING ||
                    to_state == DEVICE_STATE_IDLE);

        case DEVICE_STATE_SPEAKING:
            // Can transition to listening or idle
            return (to_state == DEVICE_STATE_LISTENING ||
                    to_state == DEVICE_STATE_IDLE);

        case DEVICE_STATE_UPGRADING:
            // Can transition back to idle or go to fatal error
            return (to_state == DEVICE_STATE_IDLE ||
                    to_state == DEVICE_STATE_FATAL_ERROR);

        case DEVICE_STATE_ACTIVATING:
            // Can transition to idle or fatal error
            return (to_state == DEVICE_STATE_IDLE ||
                    to_state == DEVICE_STATE_FATAL_ERROR);

        case DEVICE_STATE_AUDIO_TESTING:
            // Can transition to idle
            return to_state == DEVICE_STATE_IDLE;

        case DEVICE_STATE_FATAL_ERROR:
            // Can only transition to idle (recovery) or stay in error
            return (to_state == DEVICE_STATE_IDLE ||
                    to_state == DEVICE_STATE_FATAL_ERROR);

        default:
            // Invalid source state
            return false;
    }
}

