DeviceStateMachine::StateListenerId DeviceStateMachine::AddStateChangeListener(StateCallback callback)
{
    std::lock_guard<std::mutex> lock(listener_mutex_);

    // Generate unique ID for the new listener
    StateListenerId id = next_listener_id_++;

    // Store the callback with its ID
    listeners_[id] = callback;

    ESP_LOGD(TAG, "Added state change listener with ID: %d", id);

    return id;
}

cpp
void DeviceStateMachine::RemoveStateChangeListener(int listener_id)
{
    std::lock_guard<std::mutex> lock(listener_mutex_);

    // Find and remove the listener with the specified ID
    auto it = std::remove_if(listeners_.begin(), listeners_.end(),
        [listener_id](const StateChangeListener& listener) {
            return listener.id == listener_id;
        });

    if (it != listeners_.end()) {
        listeners_.erase(it, listeners_.end());
        ESP_LOGD(TAG, "Removed state change listener with ID: %d", listener_id);
    } else {
        ESP_LOGW(TAG, "Attempted to remove non-existent state change listener with ID: %d", listener_id);
    }
}

void DeviceStateMachine::NotifyStateChange(DeviceState oldState, DeviceState newState)
{
    // Copy callbacks list under mutex lock for thread safety
    std::vector<StateChangeListener> listenersCopy;
    {
        std::lock_guard<std::mutex> lock(callbacksMutex);
        listenersCopy = stateChangeListeners;
    }

    // Notify all listeners
    for (const auto& listener : listenersCopy) {
        listener(oldState, newState);
    }
}

