Ota::Ota()
{
    // Initialize serial number from eFuse
    uint8_t efuse_serial[12] = {0};
    esp_err_t err = esp_efuse_read_field_blob(ESP_EFUSE_USER_DATA, efuse_serial, 96);

    if (err == ESP_OK) {
        // Convert serial number to string format
        std::stringstream ss;
        for (int i = 0; i < 12; i++) {
            ss << std::hex << std::uppercase << std::setfill('0') << std::setw(2) << (int)efuse_serial[i];
        }

        // Check if serial number is not empty
        std::string serial = ss.str();
        if (!serial.empty()) {
            // Store the serial number for later use
            device_serial_ = serial;
            ESP_LOGI(TAG, "Device serial number loaded: %s", device_serial_.c_str());
        } else {
            ESP_LOGW(TAG, "Serial number is empty in eFuse");
        }
    } else {
        ESP_LOGE(TAG, "Failed to read serial number from eFuse: 0x%x", err);
    }

    // Check if running from factory partition
    const esp_partition_t* partition = esp_ota_get_running_partition();
    if (partition && strcmp(partition->label, "factory") == 0) {
        ESP_LOGI(TAG, "Running from factory partition, skipping");
        return;
    }

    // Get running partition info
    ESP_LOGI(TAG, "Running partition: %s", partition->label);

    // Get OTA image state
    esp_ota_img_states_t state;
    if (esp_ota_get_state_partition(partition, &state) != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get state of partition");
        return;
    }

    // Handle different OTA states
    switch (state) {
        case ESP_OTA_IMG_NEW:
            ESP_LOGI(TAG, "New OTA image detected");
            break;
        case ESP_OTA_IMG_PENDING_VERIFY:
            ESP_LOGI(TAG, "OTA image pending verification");
            break;
        case ESP_OTA_IMG_VALID:
            ESP_LOGI(TAG, "OTA image is valid");
            break;
        case ESP_OTA_IMG_INVALID:
            ESP_LOGI(TAG, "OTA image is invalid");
            break;
        default:
            ESP_LOGI(TAG, "Unknown OTA image state");
            break;
    }
}

std::string Ota::GetCheckVersionUrl()
{
    // Try to get the OTA version check URL from settings
    const char* url_from_settings = GetWifiSettingString("ota_version_check_url", nullptr);

    // If no URL is set in settings, use default
    if (url_from_settings == nullptr || strlen(url_from_settings) == 0) {
        ESP_LOGI(TAG, "No OTA version check URL found in settings, using default");
        return DEFAULT_OTA_VERSION_CHECK_URL;
    }

    // Validate the URL format
    std::string url = std::string(url_from_settings);
    if (url.find("http://") != 0 && url.find("https://") != 0) {
        ESP_LOGW(TAG, "Invalid OTA version check URL format: %s", url.c_str());
        return DEFAULT_OTA_VERSION_CHECK_URL;
    }

    ESP_LOGI(TAG, "Using OTA version check URL: %s", url.c_str());
    return url;
}

esp_err_t Ota::SetupHttp()
{
    // Create HTTP client instance
    http = new HttpClient();

    // Set basic headers
    http->SetHeader("User-Agent", "ESP32-OTA-Client/1.0");
    http->SetHeader("Content-Type", "application/json");

    // Set device identification header
    std::string device_id = GetDeviceId();
    http->SetHeader("X-Device-ID", device_id.c_str());

    // Set language header from lang_config
    const char* lang = GetLanguageCode();
    http->SetHeader("Accept-Language", lang);

    // Set conditional serial number based on provisioning status
    if (IsDeviceProvisioned()) {
        std::string serial = GetDeviceSerialNumber();
        http->SetHeader("X-Serial-Number", serial.c_str());
    }

    // Set additional security headers if needed
    #ifdef SOC_HMAC_SUPPORTED
    std::string signature = GenerateSignature();
    http->SetHeader("X-Signature", signature.c_str());
    #endif

    // Set timeout and other HTTP settings
    http->SetTimeout(30000); // 30 seconds timeout

    return ESP_OK;
}

ESP_ERR_t Ota::CheckVersion()
{
    // Get current firmware version
    const char* current_version = system_info_get_version();
    if (!current_version) {
        ESP_LOGE(TAG, "Failed to get current version");
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Current version: %s", current_version);

    // Get the running partition info
    const esp_partition_t* partition = esp_ota_get_running_partition();
    if (!partition) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Running partition: %s", partition->label);

    // Check if we're running from factory partition
    if (strcmp(partition->label, "factory") == 0) {
        ESP_LOGI(TAG, "Running from factory partition, skipping OTA check");
        return ESP_OK;
    }

    // Prepare HTTP request to version check endpoint
    std::string url = settings_get_ota_url();
    if (url.empty()) {
        ESP_LOGE(TAG, "OTA URL not configured");
        return ESP_FAIL;
    }

    // Add version parameter to URL
    url += "?version=" + std::string(current_version);

    // Send HTTP GET request
    Http* http = Http::GetInstance();
    if (!http) {
        ESP_LOGE(TAG, "Failed to get HTTP instance");
        return ESP_FAIL;
    }

    // Clear any previous response
    http->ClearResponse();

    // Make HTTP request
    int http_code = http->Get(url.c_str());
    if (http_code != 200) {
        ESP_LOGE(TAG, "HTTP request failed, code=%d", http_code);
        return ESP_FAIL;
    }

    // Get response data
    const char* response_data = http->GetResponseData();
    if (!response_data) {
        ESP_LOGE(TAG, "No response data received");
        return ESP_FAIL;
    }

    // Parse JSON response
    cJSON* root = cJSON_Parse(response_data);
    if (!root) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Extract version information
    cJSON* version_obj = cJSON_GetObjectItem(root, "version");
    if (!version_obj || !cJSON_IsString(version_obj)) {
        ESP_LOGE(TAG, "Invalid version in response");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    const char* new_version = version_obj->valuestring;
    ESP_LOGI(TAG, "Latest version: %s", new_version);

    // Compare versions
    int version_cmp = strcmp(new_version, current_version);
    if (version_cmp <= 0) {
        ESP_LOGI(TAG, "Current version is up to date");
        cJSON_Delete(root);
        return ESP_OK;
    }

    ESP_LOGI(TAG, "Newer version available, starting update process");

    // Handle activation data if present
    cJSON* activation_obj = cJSON_GetObjectItem(root, "activation");
    if (activation_obj && cJSON_IsObject(activation_obj)) {
        // Process activation data
        cJSON* key = cJSON_GetObjectItem(activation_obj, "key");
        cJSON* value = cJSON_GetObjectItem(activation_obj, "value");

        if (key && value) {
            // Store activation data
            settings_set_activation_key(key->valuestring);
            settings_set_activation_value(value->valuestring);
            ESP_LOGI(TAG, "Activation data updated");
        }
    }

    // Handle MQTT configuration if present
    cJSON* mqtt_obj = cJSON_GetObjectItem(root, "mqtt");
    if (mqtt_obj && cJSON_IsObject(mqtt_obj)) {
        // Process MQTT configuration
        cJSON* broker = cJSON_GetObjectItem(mqtt_obj, "broker");
        cJSON* port = cJSON_GetObjectItem(mqtt_obj, "port");
        cJSON* username = cJSON_GetObjectItem(mqtt_obj, "username");
        cJSON* password = cJSON_GetObjectItem(mqtt_obj, "password");

        if (broker && cJSON_IsString(broker)) {
            settings_set_mqtt_broker(broker->valuestring);
        }

        if (port && cJSON_IsNumber(port)) {
            settings_set_mqtt_port(port->valueint);
        }

        if (username && cJSON_IsString(username)) {
            settings_set_mqtt_username(username->valuestring);
        }

        if (password && cJSON_IsString(password)) {
            settings_set_mqtt_password(password->valuestring);
        }

        ESP_LOGI(TAG, "MQTT configuration updated");
    }

    // Handle firmware download URL
    cJSON* firmware_obj = cJSON_GetObjectItem(root, "firmware");
    if (!firmware_obj || !cJSON_IsObject(firmware_obj)) {
        ESP_LOGE(TAG, "Firmware URL not found in response");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    cJSON* firmware_url = cJSON_GetObjectItem(firmware_obj, "url");
    if (!firmware_url || !cJSON_IsString(firmware_url)) {
        ESP_LOGE(TAG, "Firmware URL invalid");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    // Store the firmware URL for later download
    settings_set_firmware_url(firmware_url->valuestring);

    // Get the next OTA partition
    const esp_partition_t* ota_partition = esp_ota_get_next_update_partition(NULL);
    if (!ota_partition) {
        ESP_LOGE(TAG, "Failed to get next OTA partition");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Next OTA partition: %s", ota_partition->label);

    // Mark partition as pending update
    esp_err_t err = esp_ota_set_boot_partition(ota_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set boot partition: %s", esp_err_to_name(err));
        cJSON_Delete(root);
        return err;
    }

    ESP_LOGI(TAG, "OTA update prepared successfully");
    cJSON_Delete(root);
    return ESP_OK;
}

esp_err_t Ota::MarkCurrentVersionValid()
{
    const esp_partition_t *partition = esp_ota_get_running_partition();
    if (partition == NULL) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return ESP_FAIL;
    }

    // Check if we're running from factory partition
    if (strcmp(partition->label, "factory") == 0) {
        ESP_LOGI(TAG, "Running from factory partition, skipping validation");
        return ESP_OK;
    }

    ESP_LOGI(TAG, "Running partition: %s", partition->label);

    esp_ota_img_states_t state;
    if (esp_ota_get_state_partition(partition, &state) != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get state of partition");
        return ESP_FAIL;
    }

    // Only mark as valid if currently in PENDING state
    if (state == ESP_OTA_IMG_PENDING_VERIFY) {
        ESP_LOGI(TAG, "Marking partition %s as valid", partition->label);
        if (esp_ota_mark_app_valid_cancel_rollback() != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mark app as valid");
            return ESP_FAIL;
        }
        ESP_LOGI(TAG, "Successfully marked partition as valid");
    } else if (state == ESP_OTA_IMG_VALID) {
        ESP_LOGI(TAG, "Partition %s is already valid", partition->label);
    } else if (state == ESP_OTA_IMG_INVALID) {
        ESP_LOGE(TAG, "Partition %s is invalid", partition->label);
        return ESP_FAIL;
    } else {
        ESP_LOGI(TAG, "Partition %s state: %d", partition->label, state);
    }

    return ESP_OK;
}

esp_err_t Ota::Upgrade(const std::string &url, std::function<void(int progress, size_t speed)> progress_callback)
{
    ESP_LOGI(TAG, "Starting OTA upgrade from %s", url.c_str());

    // Get OTA partition
    const esp_partition_t *partition = esp_ota_get_next_update_partition(NULL);
    if (partition == NULL) {
        ESP_LOGE(TAG, "No OTA partition found");
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "OTA partition: %s", partition->label);

    // Create HTTP client
    HttpClient *http = HttpClient::Create(url);
    if (http == NULL) {
        ESP_LOGE(TAG, "Failed to create HTTP client");
        return ESP_FAIL;
    }

    // Open HTTP connection
    if (http->Open() != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection");
        delete http;
        return ESP_FAIL;
    }

    // Check if we're running from factory partition
    const esp_partition_t *running_partition = esp_ota_get_running_partition();
    if (running_partition && strcmp(running_partition->label, "factory") == 0) {
        ESP_LOGI(TAG, "Running from factory partition, skipping");
        delete http;
        return ESP_OK;
    }

    // Start OTA update
    esp_ota_handle_t update_handle;
    esp_err_t err = esp_ota_begin(partition, OTA_SIZE_UNKNOWN, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "OTA begin failed: 0x%x", err);
        delete http;
        return err;
    }

    ESP_LOGI(TAG, "OTA update started");

    // Download and write firmware
    size_t downloaded_size = 0;
    size_t total_size = 0;
    bool download_complete = false;

    while (!download_complete) {
        // Get content length if available
        if (total_size == 0) {
            total_size = http->GetContentLength();
            if (total_size > 0) {
                ESP_LOGI(TAG, "Downloading %zu bytes", total_size);
            }
        }

        // Read data from HTTP stream
        uint8_t buffer[1024];
        size_t read_size = http->Read(buffer, sizeof(buffer));

        if (read_size <= 0) {
            // Check if we've reached end of stream
            if (http->IsFinished()) {
                download_complete = true;
                break;
            } else {
                ESP_LOGE(TAG, "HTTP read error");
                esp_ota_end(update_handle);
                delete http;
                return ESP_FAIL;
            }
        }

        // Write to OTA partition
        err = esp_ota_write(update_handle, buffer, read_size);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "OTA write failed: 0x%x", err);
            esp_ota_end(update_handle);
            delete http;
            return err;
        }

        downloaded_size += read_size;

        // Calculate progress and speed
        int progress = total_size > 0 ? (downloaded_size * 100 / total_size) : 0;
        size_t speed = read_size; // Simplified speed calculation

        // Call progress callback
        if (progress_callback) {
            progress_callback(progress, speed);
        }
    }

    // Finalize OTA update
    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "OTA end failed: 0x%x", err);
        delete http;
        return err;
    }

    // Set the new firmware as bootable
    err = esp_ota_set_boot_partition(partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set boot partition: 0x%x", err);
        delete http;
        return err;
    }

    ESP_LOGI(TAG, "OTA update completed successfully");
    delete http;
    return ESP_OK;
}

std::vector<int> Ota::ParseVersion(const std::string &version_str)
{
    std::vector<int> version_parts;

    // Handle empty string
    if (version_str.empty()) {
        return version_parts;
    }

    // Split the version string by dots
    size_t start = 0;
    size_t end = 0;

    while ((end = version_str.find('.', start)) != std::string::npos) {
        std::string part = version_str.substr(start, end - start);
        // Convert to integer and add to vector
        try {
            int num = std::stoi(part);
            version_parts.push_back(num);
        } catch (const std::exception&) {
            // If conversion fails, skip this part
            continue;
        }
        start = end + 1;
    }

    // Handle the last part
    std::string last_part = version_str.substr(start);
    if (!last_part.empty()) {
        try {
            int num = std::stoi(last_part);
            version_parts.push_back(num);
        } catch (const std::exception&) {
            // If conversion fails, skip this part
        }
    }

    return version_parts;
}

bool Ota::IsNewVersionAvailable(const std::string &current_version, const std::string &candidate_version)
{
    // Parse version strings into components
    auto parse_version = [](const std::string &version) -> std::vector<int> {
        std::vector<int> components;
        std::stringstream ss(version);
        std::string item;

        while (std::getline(ss, item, '.')) {
            try {
                components.push_back(std::stoi(item));
            } catch (const std::exception&) {
                // If conversion fails, treat as 0
                components.push_back(0);
            }
        }
        return components;
    };

    // Parse both versions
    auto current_components = parse_version(current_version);
    auto candidate_components = parse_version(candidate_version);

    // Compare component by component
    size_t max_size = std::max(current_components.size(), candidate_components.size());

    for (size_t i = 0; i < max_size; ++i) {
        int current_val = (i < current_components.size()) ? current_components[i] : 0;
        int candidate_val = (i < candidate_components.size()) ? candidate_components[i] : 0;

        if (candidate_val > current_val) {
            return true;  // Candidate is newer
        } else if (candidate_val < current_val) {
            return false; // Current is newer
        }
        // If equal, continue to next component
    }

    // Versions are equal
    return false;
}

std::string Ota::GetActivationPayload()
{
    // Create JSON object for activation payload
    cJSON *root = cJSON_CreateObject();
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to create JSON object");
        return "{}";
    }

    // Get device serial number
    std::string serial_number = SystemInfo::GetSerialNumber();
    if (serial_number.empty()) {
        ESP_LOGW(TAG, "Serial number not available, returning empty payload");
        cJSON_Delete(root);
        return "{}";
    }

    // Add serial number to payload
    cJSON_AddStringToObject(root, "serial", serial_number.c_str());

    // Generate challenge string (using timestamp or random value)
    char challenge[32];
    snprintf(challenge, sizeof(challenge), "%lu", (unsigned long)esp_timer_get_time());
    cJSON_AddStringToObject(root, "challenge", challenge);

    // Generate HMAC-SHA256 signature
    #ifdef SOC_HMAC_SUPPORTED
    // Get hardware-backed key
    uint8_t hmac_key[32];
    esp_err_t err = esp_efuse_read_field_blob(ESP_EFUSE_OPTIONAL_KEY0, hmac_key, 256);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read HMAC key from efuse");
        cJSON_Delete(root);
        return "{}";
    }

    // Create message to sign (serial + challenge)
    std::string message = serial_number + challenge;

    // Calculate HMAC-SHA256
    uint8_t hmac_result[32];
    esp_hmac_context_t ctx;
    esp_hmac_start(&ctx, ESP_HMAC_SHA256, hmac_key, 32);
    esp_hmac_update(&ctx, (uint8_t*)message.data(), message.size());
    esp_hmac_finish(&ctx, hmac_result);

    // Convert HMAC result to hex string
    char hmac_hex[65];
    for (int i = 0; i < 32; i++) {
        snprintf(hmac_hex + i*2, 3, "%02x", hmac_result[i]);
    }
    hmac_hex[64] = '\0';

    cJSON_AddStringToObject(root, "signature", hmac_hex);
    #else
    // Fallback when HMAC is not supported
    ESP_LOGW(TAG, "HMAC not supported, skipping signature generation");
    #endif

    // Convert JSON to string
    char *json_string = cJSON_Print(root);
    if (json_string == nullptr) {
        ESP_LOGE(TAG, "Failed to print JSON");
        cJSON_Delete(root);
        return "{}";
    }

    std::string result(json_string);
    cJSON_Delete(root);
    free(json_string);

    return result;
}

ESP_LOGI(TAG, "Running partition: %s", partition->label);
esp_ota_img_states_t state;
if (esp_ota_get_state_partition(partition, &state) != ESP_OK)
{
    ESP_LOGE(TAG, "Failed to get state of partition");
    cJSON_Delete(root);
    return ESP_FAIL;
}

if (state == ESP_OTA_IMG_PENDING_VERIFY)
{
    // Check if we're running from the factory partition
    const esp_partition_t *running = esp_ota_get_running_partition();
    if (running->subtype == ESP_PARTITION_SUBTYPE_APP_FACTORY)
    {
        ESP_LOGI(TAG, "Running from factory partition, skipping");
        cJSON_Delete(root);
        return ESP_OK;
    }

    // Prepare activation payload
    cJSON *payload = cJSON_CreateObject();
    if (!payload)
    {
        ESP_LOGE(TAG, "Failed to create payload");
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    // Add device information to payload
    cJSON_AddStringToObject(payload, "device_id", get_device_id());
    cJSON_AddStringToObject(payload, "version", get_version());
    cJSON_AddStringToObject(payload, "partition", partition->label);

    // Get current firmware hash
    char hash_str[65] = {0};
    if (get_firmware_hash(hash_str, sizeof(hash_str)) == ESP_OK)
    {
        cJSON_AddStringToObject(payload, "hash", hash_str);
    }

    // Construct activation URL
    std::string activation_url = get_activation_url();
    if (activation_url.empty())
    {
        ESP_LOGE(TAG, "Failed to get activation URL");
        cJSON_Delete(payload);
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    // Send HTTP POST request
    int http_code = http->Post(activation_url.c_str(), payload);
    cJSON_Delete(payload);

    if (http_code < 0)
    {
        ESP_LOGE(TAG, "HTTP POST failed, code=%d", http_code);
        cJSON_Delete(root);
        return ESP_FAIL;
    }

    // Handle response
    if (http_code == 200)
    {
        ESP_LOGI(TAG, "Firmware activation successful");
        cJSON_Delete(root);
        return ESP_OK;
    }
    else if (http_code == 400)
    {
        ESP_LOGE(TAG, "Bad request - invalid activation data");
        cJSON_Delete(root);
        return ESP_ERR_INVALID_ARG;
    }
    else if (http_code == 401)
    {
        ESP_LOGE(TAG, "Unauthorized - activation denied");
        cJSON_Delete(root);
        return ESP_ERR_UNAUTHORIZED;
    }
    else
    {
        ESP_LOGE(TAG, "Activation failed with HTTP code: %d", http_code);
        cJSON_Delete(root);
        return ESP_FAIL;
    }
}
else if (state == ESP_OTA_IMG_VALID)
{
    ESP_LOGI(TAG, "Firmware already activated");
    cJSON_Delete(root);
    return ESP_OK;
}
else
{
    ESP_LOGE(TAG, "Invalid OTA state: %d", state);
    cJSON_Delete(root);
    return ESP_FAIL;
}

Settings::~Settings()
{
    if (read_write_)
    {
        nvs_commit(nvs_handle_);
    }
    nvs_close(nvs_handle_);
}

std::string Settings::GetString(const std::string &key, const std::string &default_value)
{
    if (!read_write_ && !nvs_handle_) {
        ESP_LOGE(TAG, "Namespace %s is not open for reading", ns_.c_str());
        return default_value;
    }

    // Get the required buffer size
    size_t required_size = 0;
    esp_err_t err = nvs_get_str(nvs_handle_, key.c_str(), nullptr, &required_size);

    if (err == ESP_ERR_NVS_NOT_FOUND) {
        ESP_LOGD(TAG, "Key %s not found in namespace %s, returning default value", 
                 key.c_str(), ns_.c_str());
        return default_value;
    } else if (err != ESP_OK) {
        ESP_LOGE(TAG, "Error reading key %s from namespace %s: %s", 
                 key.c_str(), ns_.c_str(), esp_err_to_name(err));
        return default_value;
    }

    // Allocate buffer for the string
    std::string result(required_size, '\0');

    // Read the actual string value
    err = nvs_get_str(nvs_handle_, key.c_str(), result.data(), &required_size);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Error reading key %s from namespace %s: %s", 
                 key.c_str(), ns_.c_str(), esp_err_to_name(err));
        return default_value;
    }

    // Remove trailing null characters
    while (!result.empty() && result.back() == '\0') {
        result.pop_back();
    }

    return result;
}

void Settings::SetString(const std::string &key, const std::string &value)
{
    if (read_write_)
    {
        esp_err_t err = nvs_set_str(nvs_handle_, key.c_str(), value.c_str());
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to set string for key '%s': %s", key.c_str(), esp_err_to_name(err));
        }
        // Mark as dirty to indicate unsaved changes (assuming there's a dirty flag)
        // dirty_ = true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

int32_t Settings::GetInt(const std::string &key, int32_t default_value)
{
    int32_t value = default_value;
    esp_err_t err = nvs_get_i32(nvs_handle_, key.c_str(), &value);

    if (err != ESP_OK)
    {
        if (err == ESP_ERR_NVS_NOT_FOUND)
        {
            ESP_LOGD(TAG, "Key '%s' not found in namespace '%s', returning default value %d", 
                     key.c_str(), ns_.c_str(), default_value);
        }
        else
        {
            ESP_LOGE(TAG, "Error reading key '%s' from namespace '%s': %s", 
                     key.c_str(), ns_.c_str(), esp_err_to_name(err));
        }
        return default_value;
    }

    ESP_LOGD(TAG, "Successfully read key '%s' with value %d from namespace '%s'", 
             key.c_str(), value, ns_.c_str());

    return value;
}

bool Settings::SetInt(const std::string &key, int32_t value)
{
    if (read_write_)
    {
        esp_err_t err = nvs_set_i32(nvs_handle_, key.c_str(), value);
        if (err == ESP_OK)
        {
            // Mark settings as dirty to indicate changes have been made
            dirty_ = true;
            return true;
        }
        else
        {
            ESP_LOGE(TAG, "Failed to set int value for key %s: %s", key.c_str(), esp_err_to_name(err));
            return false;
        }
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
        return false;
    }
}

bool Settings::GetBool(const std::string &key, bool default_value)
{
    bool value = default_value;
    esp_err_t err;

    if (read_write_) {
        err = nvs_get_bool(nvs_handle_, key.c_str(), &value);
        if (err != ESP_OK) {
            if (err == ESP_ERR_NVS_NOT_FOUND) {
                // Key not found, return default value
                ESP_LOGD(TAG, "Key '%s' not found in namespace '%s', returning default value", 
                         key.c_str(), ns_.c_str());
            } else {
                // Other error occurred
                ESP_LOGE(TAG, "Error reading bool from NVS: 0x%x", err);
            }
        }
    } else {
        ESP_LOGW(TAG, "Namespace %s is not open for reading", ns_.c_str());
    }

    return value;
}

bool Settings::SetBool(const std::string &key, bool value)
{
    if (read_write_)
    {
        esp_err_t err = nvs_set_u8(nvs_handle_, key.c_str(), value ? 1 : 0);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to set bool value for key %s: %s", key.c_str(), esp_err_to_name(err));
            return false;
        }

        // Mark as dirty (assuming there's a dirty flag member)
        // dirty_ = true;

        return true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
        return false;
    }
}

void Settings::EraseKey(const std::string &key)
{
    if (read_write_)
    {
        esp_err_t err = nvs_erase_key(nvs_handle_, key.c_str());
        if (err != ESP_OK)
        {
            if (err == ESP_ERR_NVS_KEY_NOT_FOUND)
            {
                // Key doesn't exist, handle gracefully
                ESP_LOGD(TAG, "Key %s not found in namespace %s", key.c_str(), ns_.c_str());
            }
            else
            {
                // Other error occurred
                ESP_LOGE(TAG, "Failed to erase key %s from namespace %s: %s", 
                        key.c_str(), ns_.c_str(), esp_err_to_name(err));
            }
        }
        else
        {
            // Successfully erased key
            ESP_LOGD(TAG, "Successfully erased key %s from namespace %s", 
                    key.c_str(), ns_.c_str());
        }
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing, cannot erase key %s", 
                ns_.c_str(), key.c_str());
    }
}

void Settings::EraseAll()
{
    if (read_write_)
    {
        esp_err_t err = nvs_erase_all(nvs_handle_);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to erase all settings in namespace %s: %s", ns_.c_str(), esp_err_to_name(err));
        }
        else
        {
            ESP_LOGI(TAG, "Successfully erased all settings in namespace %s", ns_.c_str());
        }
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

