std::string SystemInfo::GetMacAddress()
{
    uint8_t mac[6];
    std::string mac_str = "";

#if CONFIG_IDF_TARGET_ESP32P4
    // For ESP32-P4, use remote WiFi MAC
    esp_wifi_remote_get_mac(mac);
#elif CONFIG_IDF_TARGET_ESP32S3 || CONFIG_IDF_TARGET_ESP32C3 || CONFIG_IDF_TARGET_ESP32C6
    // For ESP32-S3, C3, C6 - use esp_read_mac
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
#else
    // For ESP32, ESP32-S2 - use esp_efuse_mac_get_default
    esp_efuse_mac_get_default(mac);
#endif

    // Format as colon-separated hex string
    char buffer[18]; // XX:XX:XX:XX:XX:XX\0
    snprintf(buffer, sizeof(buffer), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);

    return std::string(buffer);
}

std::string SystemInfo::GetUserAgent()
{
    esp_app_desc_t app_desc;
    esp_err_t ret = esp_app_get_description(&app_desc);

    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get app description");
        return std::string("Unknown/0.0.0");
    }

    // Get board name from configuration
    const char* board_name = CONFIG_IDF_TARGET;

    // Construct user agent string in format "BOARD_NAME/version"
    std::string user_agent = std::string(board_name) + "/" + std::string(app_desc.version);

    return user_agent;
}

void SystemInfo::PrintTaskCpuUsage(TickType_t delay_ticks)
{
    ESP_LOGI(TAG, "Measuring CPU usage...");

    // Variables for task statistics
    TaskStatus_t *start_array = nullptr;
    TaskStatus_t *end_array = nullptr;
    UBaseType_t start_array_size = 0;
    UBaseType_t end_array_size = 0;
    const UBaseType_t ARRAY_SIZE_OFFSET = 10; // Extra space for potential new tasks

    // Get initial task states
    start_array_size = uxTaskGetNumberOfTasks() + ARRAY_SIZE_OFFSET;
    start_array = (TaskStatus_t *)malloc(sizeof(TaskStatus_t) * start_array_size);
    if (start_array == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate memory for start task array");
        return;
    }

    end_array_size = uxTaskGetNumberOfTasks() + ARRAY_SIZE_OFFSET;
    end_array = (TaskStatus_t *)malloc(sizeof(TaskStatus_t) * end_array_size);
    if (end_array == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate memory for end task array");
        free(start_array);
        return;
    }

    // Get initial task information
    start_array_size = uxTaskGetSystemState(start_array, start_array_size, &total_elapsed_time);

    // Wait for specified delay
    vTaskDelay(delay_ticks);

    // Get final task information
    end_array_size = uxTaskGetSystemState(end_array, end_array_size, &total_elapsed_time);

    // Check if number of tasks changed
    if (start_array_size != end_array_size) {
        ESP_LOGW(TAG, "Task count changed from %d to %d during measurement", 
                 start_array_size, end_array_size);
    }

    // Calculate and print CPU usage for each task
    ESP_LOGI(TAG, "Task CPU Usage Report:");
    ESP_LOGI(TAG, "Task Name           CPU%%   Stack High Water Mark");

    for (UBaseType_t i = 0; i < end_array_size; i++) {
        // Find corresponding task in start array
        TaskStatus_t *start_task = nullptr;
        TaskStatus_t *end_task = &end_array[i];

        // Look for matching task by task handle
        for (UBaseType_t j = 0; j < start_array_size; j++) {
            if (start_array[j].xHandle == end_task->xHandle) {
                start_task = &start_array[j];
                break;
            }
        }

        // Calculate CPU usage if we found the task in both arrays
        if (start_task != nullptr) {
            // Calculate CPU usage percentage
            uint32_t total_time = end_task->ulRunTimeCounter - start_task->ulRunTimeCounter;
            float cpu_percent = (float)(total_time * 100.0f) / (float)total_elapsed_time;

            // Print task information
            ESP_LOGI(TAG, "%-18s %5.1f%% %10u", 
                     end_task->pcTaskName,
                     cpu_percent,
                     end_task->usStackHighWaterMark);
        } else {
            // Task was created during measurement
            ESP_LOGI(TAG, "%-18s N/A    %10u", 
                     end_task->pcTaskName,
                     end_task->usStackHighWaterMark);
        }
    }

    // Free allocated memory
    free(start_array);
    free(end_array);

    ESP_LOGI(TAG, "CPU usage measurement complete.");
}

void SystemInfo::PrintTaskList()
{
    TaskStatus_t *pxTaskStatusArray;
    UBaseType_t uxArraySize, x;
    char *pcWriteBuffer;
    size_t buffer_size;

    // Get the number of tasks
    uxArraySize = uxTaskGetNumberOfTasks();

    // Allocate memory for task status array
    pxTaskStatusArray = (TaskStatus_t *)malloc(sizeof(TaskStatus_t) * uxArraySize);
    if (pxTaskStatusArray == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task status array");
        return;
    }

    // Get the task status information
    uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, NULL);

    // Calculate buffer size needed for output
    buffer_size = uxArraySize * 100; // Rough estimate
    pcWriteBuffer = (char *)malloc(buffer_size);
    if (pcWriteBuffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task list output");
        free(pxTaskStatusArray);
        return;
    }

    // Clear the buffer
    memset(pcWriteBuffer, 0, buffer_size);

    // Print header
    snprintf(pcWriteBuffer, buffer_size, "Task Name\t\tState\tPriority\tStack High Water Mark\tTask ID\n");

    // Print each task's information
    for (x = 0; x < uxArraySize; x++) {
        char *pcStatus;

        switch (pxTaskStatusArray[x].eCurrentState) {
            case eRunning:   pcStatus = "Running"; break;
            case eReady:     pcStatus = "Ready";   break;
            case eBlocked:   pcStatus = "Blocked"; break;
            case eSuspended: pcStatus = "Suspended"; break;
            case eDeleted:   pcStatus = "Deleted"; break;
            default:         pcStatus = "Unknown"; break;
        }

        char temp_buffer[256];
        snprintf(temp_buffer, sizeof(temp_buffer), "%s\t\t%s\t%d\t\t%d\t\t\t%lu\n",
                 pxTaskStatusArray[x].pcTaskName,
                 pcStatus,
                 pxTaskStatusArray[x].uxCurrentPriority,
                 pxTaskStatusArray[x].usStackHighWaterMark,
                 (unsigned long)pxTaskStatusArray[x].xTaskNumber);

        strncat(pcWriteBuffer, temp_buffer, buffer_size - strlen(pcWriteBuffer) - 1);
    }

    // Log the task information
    ESP_LOGI(TAG, "\n%s", pcWriteBuffer);

    // Clean up
    free(pxTaskStatusArray);
    free(pcWriteBuffer);
}

