bool AudioCodec::InputData(std::vector<int16_t>& data)
{
    // Check if input is enabled
    if (!enable || !input_enabled_) {
        ESP_LOGW(TAG, "Input not enabled");
        return false;
    }

    // Check if data vector has sufficient capacity
    if (data.empty()) {
        ESP_LOGE(TAG, "Input data vector is empty");
        return false;
    }

    // Read audio data from I2S interface
    size_t bytes_read = 0;
    esp_err_t result = i2s_read(I2S_NUM_0, data.data(), data.size() * sizeof(int16_t), 
                               &bytes_read, portMAX_DELAY);

    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read from I2S: %s", esp_err_to_name(result));
        return false;
    }

    // Convert bytes read to sample count (assuming 16-bit samples)
    size_t samples_read = bytes_read / sizeof(int16_t);

    // Resize vector to actual number of samples read
    data.resize(samples_read);

    // Return true if we successfully read some data
    return samples_read > 0;
}

