cpp
Es8388AudioCodec::Es8388AudioCodec(void* i2c_master_handle, i2c_port_t i2c_port, int input_sample_rate, int output_sample_rate,
    gpio_num_t pa_pin, gpio_num_t reset_pin, gpio_num_t mute_pin, gpio_num_t adc_mic_bias_pin, 
    gpio_num_t dac_mic_bias_pin, gpio_num_t ref_input_pin, uint8_t i2c_address, bool enable_ref_input)
{
    // Store constructor parameters
    this->i2c_master_handle = i2c_master_handle;
    this->i2c_port = i2c_port;
    this->input_sample_rate = input_sample_rate;
    this->output_sample_rate = output_sample_rate;
    this->pa_pin = pa_pin;
    this->reset_pin = reset_pin;
    this->mute_pin = mute_pin;
    this->adc_mic_bias_pin = adc_mic_bias_pin;
    this->dac_mic_bias_pin = dac_mic_bias_pin;
    this->ref_input_pin = ref_input_pin;
    this->i2c_address = i2c_address;
    this->enable_ref_input = enable_ref_input;

    // Initialize GPIO pins
    if (pa_pin != GPIO_NUM_NC) {
        gpio_config_t pa_config = {
            .pin_bit_mask = 1ULL << pa_pin,
            .mode = GPIO_MODE_OUTPUT,
            .pull_up_en = GPIO_PULLUP_DISABLE,
            .pull_down_en = GPIO_PULLDOWN_DISABLE,
            .intr_type = GPIO_INTR_DISABLE
        };
        gpio_config(&pa_config);
        gpio_set_level(pa_pin, 0); // Initially off
    }

    if (reset_pin != GPIO_NUM_NC) {
        gpio_config_t reset_config = {
            .pin_bit_mask = 1ULL << reset_pin,
            .mode = GPIO_MODE_OUTPUT,
            .pull_up_en = GPIO_PULLUP_DISABLE,
            .pull_down_en = GPIO_PULLDOWN_DISABLE,
            .intr_type = GPIO_INTR_DISABLE
        };
        gpio_config(&reset_config);
        gpio_set_level(reset_pin, 0); // Reset active low
    }

    if (mute_pin != GPIO_NUM_NC) {
        gpio_config_t mute_config = {
            .pin_bit_mask = 1ULL << mute_pin,
            .mode = GPIO_MODE_OUTPUT,
            .pull_up_en = GPIO_PULLUP_DISABLE,
            .pull_down_en = GPIO_PULLDOWN_DISABLE,
            .intr_type = GPIO_INTR_DISABLE
        };
        gpio_config(&mute_config);
        gpio_set_level(mute_pin, 1); // Mute active high (assuming active low for mute)
    }

    if (adc_mic_bias_pin != GPIO_NUM_NC) {
        gpio_config_t adc_bias_config = {
            .pin_bit_mask = 1ULL << adc_mic_bias_pin,
            .mode = GPIO_MODE_OUTPUT,
            .pull_up_en = GPIO_PULLUP_DISABLE,
            .pull_down_en = GPIO_PULLDOWN_DISABLE,
            .intr_type = GPIO_INTR_DISABLE
        };
        gpio_config(&adc_bias_config);
        gpio_set_level(adc_mic_bias_pin, 0); // Initially off
    }

    if (dac_mic_bias_pin != GPIO_NUM_NC) {
        gpio_config_t dac_bias_config = {
            .pin_bit_mask = 1ULL << dac_mic_bias_pin,
            .mode = GPIO_MODE_OUTPUT,
            .pull_up_en = GPIO_PULLUP_DISABLE,
            .pull_down_en = GPIO_PULLDOWN_DISABLE,
            .intr_type = GPIO_INTR_DISABLE
        };
        gpio_config(&dac_bias_config);
        gpio_set_level(dac_mic_bias_pin, 0); // Initially off
    }

    if (ref_input_pin != GPIO_NUM_NC) {
        gpio_config_t ref_config = {
            .pin_bit_mask = 1ULL << ref_input_pin,
            .mode = GPIO_MODE_INPUT,
            .pull_up_en = GPIO_PULLUP_DISABLE,
            .pull_down_en = GPIO_PULLDOWN_DISABLE,
            .intr_type = GPIO_INTR_DISABLE
        };
        gpio_config(&ref_config);
    }

    // Reset the codec
    if (reset_pin != GPIO_NUM_NC) {
        gpio_set_level(reset_pin, 0);
        vTaskDelay(pdMS_TO_TICKS(10));
        gpio_set_level(reset_pin, 1);
        vTaskDelay(pdMS_TO_TICKS(10));
    }

    // Initialize I2C communication
    esp_err_t err = i2c_master_init(i2c_master_handle, i2c_port);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize I2C master");
        return;
    }

    // Configure ES8388 codec registers
    // Power up the codec
    write_reg(0x00, 0x00); // Reset register

    // Configure ADC and DAC clocks
    write_reg(0x01, 0x00); // Clock control register
    write_reg(0x02, 0x00); // Audio interface register

    // Configure ADC
    write_reg(0x03, 0x00); // ADC control register
    write_reg(0x04, 0x00); // ADC volume control

    // Configure DAC
    write_reg(0x05, 0x00); // DAC control register
    write_reg(0x06, 0x00); // DAC volume control

    // Configure power management
    write_reg(0x07, 0x00); // Power control register

    // Set sample rates
    set_sample_rates(input_sample_rate, output_sample_rate);

    // Configure input/output channels
    configure_channels();

    // Enable reference input if required
    if (enable_ref_input && ref_input_pin != GPIO_NUM_NC) {
        write_reg(0x08, 0x01); // Enable reference input
    } else {
        write_reg(0x08, 0x00); // Disable reference input
    }

    // Enable full-duplex mode
    write_reg(0x09, 0x03); // Full-duplex configuration

    ESP_LOGI(TAG, "ES8388 Audio Codec initialized successfully");
}

void Es8388AudioCodec::write_reg(uint8_t reg_addr, uint8_t reg_val)
{
    i2c_cmd_handle_t cmd = i2c_cmd_link_create();
    i2c_master_start(cmd);
    i2c_master_write_byte(cmd, (i2c_address << 1) | I2C_MASTER_WRITE, true);
    i2c_master_write_byte(cmd, reg_addr, true);
    i2c_master_write_byte(cmd, reg_val, true);
    i2c_master_stop(cmd);
    i2c_master_cmd_begin(i2c_port, cmd, 1000 / portTICK_PERIOD_MS);
    i2c_cmd_link_delete(cmd);
}

void Es8388AudioCodec::set_sample_rates(int input_rate, int output_rate)
{
    // Configure sample rate for ADC
    uint8_t adc_sr_reg = 0x00;
    switch(input_rate) {
        case 8000:
            adc_sr_reg = 0x00;
            break;
        case 16000:
            adc_sr_reg = 0x01;
            break;
        case 32000:
            adc_sr_reg = 0x02;
            break;
        case 44100:
            adc_sr_reg = 0x03;
            break;
        case 48000:
            adc_sr_reg = 0x04;
            break;
        default:
            adc_sr_reg = 0x04; // Default to 48kHz
    }

    write_reg(0x03, adc_sr_reg);

    // Configure sample rate for DAC
    uint8_t dac_sr_reg = 0x00;
    switch(output_rate) {
        case 8000:
            dac_sr_reg = 0x00;
            break;
        case 16000:
            dac_sr_reg = 0x01;
            break;
        case 32000:
            dac_sr_reg = 0x02;
            break;
        case 44100:
            dac_sr_reg = 0x03;
            break;
        case 48000:
            dac_sr_reg = 0x04;
            break;
        default:
            dac_sr_reg = 0x04; // Default to 48kHz
    }

    write_reg(0x05, dac_sr_reg);
}

void Es8388AudioCodec::configure_channels()
{
    // Configure mono/stereo mode for ADC and DAC
    write_reg(0x04, 0x00); // ADC channel configuration
    write_reg(0x06, 0x00); // DAC channel configuration

    // Configure I2S interface
    write_reg(0x02, 0x00); // Audio interface format selection
}

Es8388AudioCodec::~Es8388AudioCodec() {
    ESP_LOGD(TAG, "Destroying Es8388AudioCodec");

    // Close and delete input device if it exists
    if (input_device_ != nullptr) {
        input_device_->Close();
        delete input_device_;
        input_device_ = nullptr;
    }

    // Close and delete output device if it exists
    if (output_device_ != nullptr) {
        output_device_->Close();
        delete output_device_;
        output_device_ = nullptr;
    }

    // Delete control interface if it exists
    if (control_interface_ != nullptr) {
        delete control_interface_;
        control_interface_ = nullptr;
    }

    // Delete GPIO interface if it exists
    if (gpio_interface_ != nullptr) {
        delete gpio_interface_;
        gpio_interface_ = nullptr;
    }

    // Delete data interface if it exists
    if (data_interface_ != nullptr) {
        delete data_interface_;
        data_interface_ = nullptr;
    }

    ESP_LOGD(TAG, "Es8388AudioCodec destroyed successfully");
}

