void Es8388AudioCodec::SetOutputVolume(int volume)
{
    // Store the new volume level in internal state
    m_output_volume = volume;

    // Ensure volume is within valid range (0-100 typically)
    if (volume < 0) volume = 0;
    if (volume > 100) volume = 100;

    // Calculate register value for volume control
    // ES8388 typically uses 6-bit volume control registers
    // Volume range: 0-63 (0x00-0x3F)
    uint8_t volume_reg_value = (volume * 63) / 100;

    // Apply volume setting to hardware
    // Write to DAC volume control registers
    // Assuming registers for left and right channel volume control
    uint8_t reg_addr = 0x1A; // Example register address for DAC volume control

    // Write volume value to left channel
    i2c_master_write_byte(m_i2c_master_handle, reg_addr, ACK_CHECK_EN);
    i2c_master_write_byte(m_i2c_master_handle, volume_reg_value, ACK_CHECK_EN);

    // Write same volume value to right channel (if needed)
    reg_addr = 0x1B; // Example register address for right channel
    i2c_master_write_byte(m_i2c_master_handle, reg_addr, ACK_CHECK_EN);
    i2c_master_write_byte(m_i2c_master_handle, volume_reg_value, ACK_CHECK_EN);

    // Send stop condition
    i2c_master_stop(m_i2c_master_handle);

    // Log the volume change for debugging
    ESP_LOGD(TAG, "Output volume set to %d%% (%d)", volume, volume_reg_value);
}

void Es8388AudioCodec::EnableInput(bool enable)
{
    if (enable) {
        // Enable input functionality
        ESP_LOGI(TAG, "Enabling audio input");

        // Configure input settings
        audio_hal_codec_config_t codec_cfg = {
            .port = AUDIO_HAL_CODEC_MODE_LINEIN,
            .sample_rates = input_sample_rate_,
            .bit_width = AUDIO_HAL_BIT_LENGTH_16BITS,
            .channels = 2,
            .gain = input_gain_
        };

        // Set up the input device with configuration
        esp_err_t ret = audio_codec_set_input(&codec_cfg);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to set input configuration");
            return;
        }

        // Open input device for audio capture
        ret = audio_codec_open_input();
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to open input device");
            return;
        }

        // Apply input gain - either fixed or adjustable
        if (input_gain_ > 0) {
            // Apply adjustable gain
            ret = audio_codec_set_input_gain(input_gain_);
            if (ret != ESP_OK) {
                ESP_LOGE(TAG, "Failed to set input gain");
                return;
            }
        } else {
            // Apply fixed gain (default value)
            ret = audio_codec_set_input_gain(20); // Default fixed gain value
            if (ret != ESP_OK) {
                ESP_LOGE(TAG, "Failed to set default input gain");
                return;
            }
        }

        ESP_LOGI(TAG, "Audio input enabled successfully");
    } else {
        // Disable input functionality
        ESP_LOGI(TAG, "Disabling audio input");

        // Close input device to stop audio capture
        esp_err_t ret = audio_codec_close_input();
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to close input device");
            return;
        }

        ESP_LOGI(TAG, "Audio input disabled successfully");
    }
}

void Es8388AudioCodec::EnableOutput(bool enable)
{
    if (enable) {
        // Enable audio output
        // Configure sample rate
        SetSampleRate(output_sample_rate_);

        // Set volume level
        SetVolume(50); // Default volume - should be configurable

        // Configure analog output levels
        // Enable headphone amplifiers
        WriteRegister(0x12, 0x03); // Enable HP amplifiers
        WriteRegister(0x13, 0x03); // Enable speaker amplifiers

        // Power up the codec
        WriteRegister(0x00, 0x80); // Power up codec

        // Enable output drivers
        WriteRegister(0x10, 0x30); // Enable output drivers

        // Activate power amplifier pin if present
        if (power_amp_pin_ != GPIO_NUM_NC) {
            gpio_set_level(power_amp_pin_, 1);
        }

        ESP_LOGI(TAG, "Audio output enabled");
    } else {
        // Disable audio output
        // Disable output drivers
        WriteRegister(0x10, 0x00); // Disable output drivers

        // Power down the codec
        WriteRegister(0x00, 0x00); // Power down codec

        // Disable amplifiers
        WriteRegister(0x12, 0x00); // Disable HP amplifiers
        WriteRegister(0x13, 0x00); // Disable speaker amplifiers

        // Deactivate power amplifier pin if present
        if (power_amp_pin_ != GPIO_NUM_NC) {
            gpio_set_level(power_amp_pin_, 0);
        }

        ESP_LOGI(TAG, "Audio output disabled");
    }
}

int Es8388AudioCodec::Read(int16_t* buffer, int samples)
{
    if (!input_enabled_) {
        ESP_LOGW(TAG, "Input not enabled, cannot read audio data");
        return 0;
    }

    if (buffer == nullptr || samples <= 0) {
        ESP_LOGE(TAG, "Invalid buffer or sample count");
        return 0;
    }

    // Use ESP-IDF codec device API to read audio data
    // Assuming there's a codec device handle available in the class
    int actual_samples = 0;

    // Read the specified number of 16-bit PCM samples
    esp_err_t err = codec_dev_->read(codec_dev_, buffer, samples * sizeof(int16_t), &actual_samples);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read audio data from codec: %s", esp_err_to_name(err));
