void AfeWakeWord::AudioDetectionTask()
{
    // Initialize audio detection variables
    bool detection_running = false;
    uint32_t detection_count = 0;

    // Main task loop
    while (true) {
        // Wait for either detection start signal or stop signal
        EventBits_t bits = xEventGroupWaitBits(event_group_, 
                                              DETECTION_RUNNING_EVENT | 0x02, // Assuming 0x02 is stop bit
                                              pdTRUE,  // Clear bits on exit
                                              pdFALSE, // Wait for any bit
                                              portMAX_DELAY);

        // Check if detection should run
        if (bits & DETECTION_RUNNING_EVENT) {
            detection_running = true;
            detection_count = 0;

            // Start audio capture and processing
            while (detection_running && (detection_count < 1000)) { // Prevent infinite loop
                // Check for wake word detection from audio front-end
                if (afe_->DetectWakeWord()) {
                    // Wake word detected - stop detection
                    detection_running = false;

                    // Stop audio capture
                    codec_->Stop();

                    // Store audio data (implement as needed)
                    // This would typically involve saving recent audio samples

                    // Trigger callback with detected wake word
                    if (wake_word_callback_) {
                        wake_word_callback_(wake_word_);
                    }

                    // Reset detection state
                    detection_count = 0;
                    break;
                }

                // Small delay to prevent excessive CPU usage
                vTaskDelay(pdMS_TO_TICKS(10));
                detection_count++;
            }

            // If we exited due to timeout, continue waiting for next trigger
            if (detection_count >= 1000) {
                detection_running = false;
            }
        } else if (bits & 0x02) { // Stop signal
            // Stop detection if running
            if (detection_running) {
                detection_running = false;
                codec_->Stop();
            }
        }

        // Small delay between iterations
        vTaskDelay(pdMS_TO_TICKS(5));
    }
}

void AfeWakeWord::StoreWakeWordData(const int16_t *data, size_t length)
{
    if (data == nullptr || length == 0) {
        return;
    }

    // Calculate how many samples constitute ~2 seconds of audio
    // Assuming 16kHz sample rate, 2 seconds = 32000 samples
    const size_t max_samples = 32000;  // 2 seconds at 16kHz

    // Lock the buffer to prevent concurrent access
    portENTER_CRITICAL(&buffer_spinlock_);

    // If we're starting fresh or buffer is empty, reset position
    if (wake_word_buffer_size_ == 0) {
        wake_word_buffer_position_ = 0;
    }

    // Calculate how many samples we can fit in remaining buffer space
    size_t available_space = max_samples - wake_word_buffer_size_;
    size_t samples_to_store = (length < available_space) ? length : available_space;

    // Copy data to buffer
    size_t buffer_index = wake_word_buffer_position_ % max_samples;
    size_t copy_length = (buffer_index + samples_to_store > max_samples) ? 
                         (max_samples - buffer_index) : samples_to_store;

    // First copy chunk
    memcpy(&wake_word_buffer_[buffer_index], data, copy_length * sizeof(int16_t));

    // Second copy chunk if needed (wraps around)
    if (copy_length < samples_to_store) {
        memcpy(&wake_word_buffer_[0], &data[copy_length], 
               (samples_to_store - copy_length) * sizeof(int16_t));
    }

    // Update buffer state
    wake_word_buffer_position_ += samples_to_store;
    wake_word_buffer_size_ += samples_to_store;

    // Ensure we don't exceed max size
    if (wake_word_buffer_size_ > max_samples) {
        wake_word_buffer_size_ = max_samples;
    }

    // Unlock the buffer
    portEXIT_CRITICAL(&buffer_spinlock_);
}

