esp_err_t CustomWakeWord::ParseWakenetModelConfig(const char* config_json)
{
    cJSON* json = cJSON_Parse(config_json);
    if (json == NULL) {
        ESP_LOGE(TAG, "Failed to parse JSON configuration");
        return ESP_FAIL;
    }

    // Parse language
    cJSON* language = cJSON_GetObjectItem(json, "language");
    if (language && cJSON_IsString(language)) {
        strncpy(wake_word_language_, language->valuestring, sizeof(wake_word_language_) - 1);
        wake_word_language_[sizeof(wake_word_language_) - 1] = '\0';
        ESP_LOGI(TAG, "Parsed language: %s", wake_word_language_);
    }

    // Parse duration
    cJSON* duration = cJSON_GetObjectItem(json, "duration");
    if (duration && cJSON_IsNumber(duration)) {
        wake_word_duration_ = duration->valuedouble;
        ESP_LOGI(TAG, "Parsed duration: %.2f", wake_word_duration_);
    }

    // Parse threshold
    cJSON* threshold = cJSON_GetObjectItem(json, "threshold");
    if (threshold && cJSON_IsNumber(threshold)) {
        wake_word_threshold_ = threshold->valuedouble;
        ESP_LOGI(TAG, "Parsed threshold: %.2f", wake_word_threshold_);
    }

    // Parse commands
    cJSON* commands = cJSON_GetObjectItem(json, "commands");
    if (commands && cJSON_IsArray(commands)) {
        int num_commands = cJSON_GetArraySize(commands);
        ESP_LOGI(TAG, "Found %d commands", num_commands);

        // Clear existing commands
        wake_word_commands_.clear();

        for (int i = 0; i < num_commands; i++) {
            cJSON* command_obj = cJSON_GetArrayItem(commands, i);
            if (command_obj && cJSON_IsObject(command_obj)) {
                Command cmd;

                // Parse command name
                cJSON* name = cJSON_GetObjectItem(command_obj, "name");
                if (name && cJSON_IsString(name)) {
                    strncpy(cmd.name, name->valuestring, sizeof(cmd.name) - 1);
                    cmd.name[sizeof(cmd.name) - 1] = '\0';
                }

                // Parse command trigger words
                cJSON* trigger_words = cJSON_GetObjectItem(command_obj, "trigger_words");
                if (trigger_words && cJSON_IsArray(trigger_words)) {
                    int num_trigger_words = cJSON_GetArraySize(trigger_words);
                    cmd.trigger_words.clear();

                    for (int j = 0; j < num_trigger_words; j++) {
                        cJSON* word = cJSON_GetArrayItem(trigger_words, j);
                        if (word && cJSON_IsString(word)) {
                            cmd.trigger_words.push_back(std::string(word->valuestring));
                        }
                    }
                }

                // Parse command action
                cJSON* action = cJSON_GetObjectItem(command_obj, "action");
                if (action && cJSON_IsString(action)) {
                    strncpy(cmd.action, action->valuestring, sizeof(cmd.action) - 1);
                    cmd.action[sizeof(cmd.action) - 1] = '\0';
                }

                wake_word_commands_.push_back(cmd);
                ESP_LOGI(TAG, "Parsed command: %s", cmd.name);
            }
        }
    }

    cJSON_Delete(json);
    return ESP_OK;
}

bool CustomWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *model_list)
{
    // Initialize audio codec
    if (codec == nullptr) {
        ESP_LOGE(TAG, "Audio codec is null");
        return false;
    }

    // Configure audio codec
    if (!codec->Initialize()) {
        ESP_LOGE(TAG, "Failed to initialize audio codec");
        return false;
    }

    // Load wake word models
    if (model_list == nullptr) {
        ESP_LOGE(TAG, "Model list is null");
        return false;
    }

    // Initialize multinet model for speech command recognition
    esp_mn_iface_t *multinet_iface = esp_mn_get_interface(model_list->model_name);
    if (multinet_iface == nullptr) {
        ESP_LOGE(TAG, "Failed to get multinet interface for model: %s", model_list->model_name);
        return false;
    }

    // Set up model parameters
    esp_mn_model_t *model = esp_mn_load_model(multinet_iface, model_list->model_name);
    if (model == nullptr) {
        ESP_LOGE(TAG, "Failed to load model: %s", model_list->model_name);
        return false;
    }

    // Configure detection parameters
    esp_mn_config_t config = {
        .threshold = model_list->threshold,
        .silence_threshold = model_list->silence_threshold,
        .language = model_list->language,
        .enable_keyword_spotting = true,
        .enable_voice_command = true
    };

    // Initialize the multinet with configuration
    esp_err_t ret = esp_mn_init_multinet(model, &config);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize multinet: %d", ret);
        esp_mn_unload_model(model);
        return false;
    }

    // Register custom voice commands if available
    if (model_list->commands && model_list->num_commands > 0) {
        for (int i = 0; i < model_list->num_commands; i++) {
            // Register each command
            ret = esp_mn_register_command(model, model_list->commands[i].command_name, 
                                       model_list->commands[i].command_id);
            if (ret != ESP_OK) {
                ESP_LOGW(TAG, "Failed to register command: %s", model_list->commands[i].command_name);
            }
        }
    }

    // Store references for later use
    this->audio_codec_ = codec;
    this->model_ = model;
    this->model_interface_ = multinet_iface;

    ESP_LOGI(TAG, "Custom wake word initialized successfully");
    return true;
}

void CustomWakeWord::Feed(const std::vector<int16_t>& audio_data)
{
    // Check if we're in a valid state for processing
    if (!is_active_) {
        return;
    }

    // Handle stereo to mono conversion if needed
    std::vector<int16_t> processed_audio;
    if (audio_data.size() % 2 == 0) {
        // Assume stereo input, extract left channel
        processed_audio.reserve(audio_data.size() / 2);
        for (size_t i = 0; i < audio_data.size(); i += 2) {
            processed_audio.push_back(audio_data[i]);
        }
    } else {
        // Already mono or unknown format, use as-is
        processed_audio = audio_data;
    }

    // Store audio data for wake word detection
    wake_word_pcm_.insert(wake_word_pcm_.end(), processed_audio.begin(), processed_audio.end());

    // Keep only the most recent audio data (avoid memory overflow)
    const size_t max_samples = 48000 * 5; // 5 seconds of 16kHz audio
    if (wake_word_pcm_.size() > max_samples) {
        wake_word_pcm_.erase(wake_word_pcm_.begin(), wake_word_pcm_.begin() + (wake_word_pcm_.size() - max_samples));
    }

    // Run wake word detection if we have enough data
    if (wake_word_pcm_.size() >= 16000) { // At least 1 second of audio at 16kHz
        esp_mn_state_t mn_state = esp_mn_run(model_handle_, wake_word_pcm_.data(), &detected_wake_word_);

        switch (mn_state) {
            case ESP_MN_STATE_DETECTED:
                // Wake word detected
                ESP_LOGI(TAG, "Wake word '%s' detected", detected_wake_word_);
                if (wake_word_callback_) {
                    wake_word_callback_(detected_wake_word_);
                }
                // Stop processing until reactivated
                is_active_ = false;
                break;

            case ESP_MN_STATE_TIMEOUT:
                // Timeout occurred, continue processing
                ESP_LOGD(TAG, "Wake word detection timeout");
                break;

            case ESP_MN_STATE_RUNNING:
                // Detection still in progress
                ESP_LOGD(TAG, "Wake word detection running");
                break;

            default:
                ESP_LOGW(TAG, "Unknown wake word detection state: %d", mn_state);
                break;
        }
    }
}

int CustomWakeWord::GetFeedSize()
{
    // Check if the model is initialized
    if (wake_word_pcm_.model == nullptr || wake_word_opus_.model == nullptr) {
        ESP_LOGW(TAG, "Model not initialized, returning 0");
        return 0;
    }

    // Get the feed size from the wake word detection model
    // This is typically the number of samples required for one processing step
    const esp_mn_iface_t* iface = esp_mn_get_interface(wake_word_pcm_.model);
    if (iface == nullptr) {
        ESP_LOGE(TAG, "Failed to get model interface");
        return 0;
    }

    // Return the required feed size for audio processing
    return iface->get_feed_size();
}

void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t>& audio_data)
{
    // Calculate how many samples constitute 2 seconds of audio
    // Assuming 16kHz sample rate (common for voice applications)
    const int SAMPLE_RATE = 16000;
    const int SECONDS_TO_STORE = 2;
    const int MAX_SAMPLES = SAMPLE_RATE * SECONDS_TO_STORE;

    // Add new audio data to the buffer
    wake_word_pcm_.insert(wake_word_pcm_.end(), audio_data.begin(), audio_data.end());

    // If we exceed the maximum buffer size, remove old samples
    if (wake_word_pcm_.size() > MAX_SAMPLES) {
        // Remove the excess samples from the beginning
        size_t excess_samples = wake_word_pcm_.size() - MAX_SAMPLES;
        wake_word_pcm_.erase(wake_word_pcm_.begin(), wake_word_pcm_.begin() + excess_samples);
    }
}

void CustomWakeWord::EncodeWakeWordData()
{
    // Create a new task for encoding wake word data
    TaskHandle_t encode_task_handle = NULL;

    // Allocate memory for the task stack
    const size_t stack_size = 8192;
    void* task_stack = heap_caps_malloc(stack_size, MALLOC_CAP_DEFAULT);
    if (task_stack == NULL) {
        ESP_LOGE(TAG, "Failed to allocate stack memory for encode task");
        return;
    }

    // Allocate memory for the task buffer
    const size_t buffer_size = 4096;
    uint8_t* task_buffer = (uint8_t*)heap_caps_malloc(buffer_size, MALLOC_CAP_DEFAULT);
    if (task_buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate buffer memory for encode task");
        heap_caps_free(task_stack);
        return;
    }

    // Create the task
    BaseType_t result = xTaskCreatePinnedToCore(
        EncodeWakeWordDataTask,
        "wake_word_encode",
        stack_size,
        this,
        configMAX_PRIORITIES - 1,
        &encode_task_handle,
        tskNO_AFFINITY
    );

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create encode task");
        heap_caps_free(task_stack);
        heap_caps_free(task_buffer);
        return;
    }

    // Store handles for cleanup later
    encode_task_handle_ = encode_task_handle;
    task_stack_ = task_stack;
    task_buffer_ = task_buffer;
}

// Helper function for the encoding task
void CustomWakeWord::EncodeWakeWordDataTask(void* pvParameters)
{
    CustomWakeWord* instance = static_cast<CustomWakeWord*>(pvParameters);

    // Initialize Opus encoder
    OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
    if (encoder == NULL) {
        ESP_LOGE(TAG, "Failed to create Opus encoder");
        vTaskDelete(NULL);
        return;
    }

    // Set encoder parameters for low complexity
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000));

    // Process PCM segments
    int sample_rate = 16000;
    int frame_size = 160; // 10ms at 16kHz
    int16_t* pcm_buffer = (int16_t*)malloc(frame_size * sizeof(int16_t));
    if (pcm_buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate PCM buffer");
        opus_encoder_destroy(encoder);
        vTaskDelete(NULL);
        return;
    }

    uint8_t* opus_buffer = (uint8_t*)malloc(1024);
    if (opus_buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate Opus buffer");
        free(pcm_buffer);
        opus_encoder_destroy(encoder);
        vTaskDelete(NULL);
        return;
    }

    // Simulate processing PCM data segments
    // In real implementation, this would read from stored PCM data
    int total_samples = 0;
    int samples_to_process = 0;

    while (total_samples < instance->wake_word_pcm_.size()) {
        samples_to_process = (instance->wake_word_pcm_.size() - total_samples > frame_size) ? 
                            frame_size : (instance->wake_word_pcm_.size() - total_samples);

        // Copy PCM data to buffer
        memcpy(pcm_buffer, &instance->wake_word_pcm_[total_samples], samples_to_process * sizeof(int16_t));

        // Encode to Opus
        int encoded_size = opus_encode(encoder, pcm_buffer, frame_size, opus_buffer, 1024);
        if (encoded_size > 0) {
            // Add encoded data to output buffer
            instance->wake_word_opus_.insert(instance->wake_word_opus_.end(), opus_buffer, opus_buffer + encoded_size);
        }

        total_samples += samples_to_process;
    }

    // Add termination marker
    uint8_t termination_marker[4] = {0xFF, 0xFF, 0xFF, 0xFF};
    instance->wake_word_opus_.insert(instance->wake_word_opus_.end(), termination_marker, termination_marker + 4);

    // Signal that encoding is complete
    instance->encoding_complete_ = true;
    xSemaphoreGive(instance->encode_complete_sem_);

    // Cleanup
    free(pcm_buffer);
    free(opus_buffer);
    opus_encoder_destroy(encoder);

    vTaskDelete(NULL);
}

bool CustomWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opus_data)
{
    // Wait for data to be available in the queue
    std::unique_lock<std::mutex> lock(wake_word_opus_mutex_);

    // Wait until there's data available or timeout
    while (wake_word_opus_queue_.empty()) {
        if (wake_word_opus_cv_.wait_for(lock, std::chrono::milliseconds(100)) 
            == std::cv_status::timeout) {
            // Timeout occurred, return false
            return false;
        }
    }

    // Get the data from the queue
    opus_data.swap(wake_word_opus_queue_.front());
    wake_word_opus_queue_.pop();

    // Return true if we got valid data (non-empty)
    return !opus_data.empty();
}

