    i2c_master_transmit(device_handle_, &output_reg1, 1, 1000 / portTICK_PERIOD_MS);
}

bool SetOutputState(uint8_t pin, uint8_t level)
{
    // Read current port state
    uint8_t current_state;
    if (ReadRegister(0x02, &current_state) != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read port state");
        return false;
    }

    // Modify the specific bit
    if (level) {
        current_state |= (1 << pin);  // Set bit high
    } else {
        current_state &= ~(1 << pin); // Set bit low
    }

    // Write back to the port register
    if (WriteRegister(0x02, current_state) != ESP_OK) {
        ESP_LOGE(TAG, "Failed to write port state");
        return false;
    }

    return true;
}

