        .sda_io_num = GPIO_NUM_18,
        .scl_io_num = GPIO_NUM_8,
        .clk_source = I2C_CLK_SRC_DEFAULT,
        .glitch_ignore_cnt = 7,
        .flags.enable_internal_pullup = true,
    };

    ESP_ERROR_CHECK(i2c_master_bus_create(&i2c_bus_config, &i2c_bus));

    // Configure XL9555 GPIO directions and initial states
    // Assuming XL9555 address is 0x20
    uint8_t xl9555_addr = 0x20;

    // Set direction register - all outputs
    uint8_t config_data[2] = {0x06, 0x00}; // Port 0 config, Port 1 config
    ESP_ERROR_CHECK(i2c_master_transmit(i2c_bus, config_data, 2, 1000 / portTICK_PERIOD_MS));

    // Power up sequence - enable camera power first
    uint8_t power_on_data[2] = {0x02, 0x00}; // Set port 1 to 0x00 (power on)
    ESP_ERROR_CHECK(i2c_master_transmit(i2c_bus, power_on_data, 2, 1000 / portTICK_PERIOD_MS));

    // Wait for power to stabilize
    vTaskDelay(50 / portTICK_PERIOD_MS);

