    vTaskDelay(10 / portTICK_PERIOD_MS);

    // Release reset
    reset_data[1] = 0x00; // Set reset high
    ESP_ERROR_CHECK(i2c_master_transmit(i2c_bus, reset_data, 2, 1000 / portTICK_PERIOD_MS));

