cpp
float FrequencyDetector::GetAmplitude() const
{
    // Check if we have enough samples in the buffer
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    // Get the last two samples from the buffer
    float sample1 = state_buffer_[state_buffer_.size() - 1];
    float sample2 = state_buffer_[state_buffer_.size() - 2];

    // Calculate the real and imaginary components using the precomputed cosine and sine coefficients
    // This implements a simple matched filter approach for frequency detection
    float real_part = sample1 * cos_coeff_ + sample2 * cos_coeff_;
    float imag_part = sample1 * sin_coeff_ + sample2 * sin_coeff_;

    // Calculate amplitude as sqrt(real^2 + imag^2)
    // Normalize by half the window size as mentioned in the description
    float amplitude = sqrtf(real_part * real_part + imag_part * imag_part);

    // Normalize by half the window size
    if (window_size_ > 0) {
        amplitude /= (window_size_ / 2.0f);
    }

    return amplitude;
}

