    std::vector<float> ProcessAudioSamples(const std::vector<float>& samples)
    {
        // Constants for AFSK tone detection
        const float MARK_FREQ = 1200.0f;    // Mark tone frequency (1200 Hz)
        const float SPACE_FREQ = 2200.0f;   // Space tone frequency (2200 Hz)
        const int SAMPLE_RATE = 8000;       // Audio sample rate
        const int WINDOW_SIZE = 160;        // 20ms window at 8kHz (8000/1200 ≈ 6.67 samples per cycle)
        const int BUFFER_SIZE = 1024;       // Buffer size for audio samples

        // Goertzel algorithm parameters
        const int MARK_N = static_cast<int>(SAMPLE_RATE / MARK_FREQ);
        const int SPACE_N = static_cast<int>(SAMPLE_RATE / SPACE_FREQ);

        // Precompute cosine values for Goertzel algorithm
        const float MARK_COEF = 2.0f * cos(2.0f * M_PI * MARK_FREQ / SAMPLE_RATE);
        const float SPACE_COEF = 2.0f * cos(2.0f * M_PI * SPACE_FREQ / SAMPLE_RATE);

        static std::vector<float> sample_buffer;
        static int buffer_index = 0;
        static bool first_run = true;

        // Add new samples to buffer
        sample_buffer.insert(sample_buffer.end(), samples.begin(), samples.end());

        // If we don't have enough samples yet, return empty vector
        if (sample_buffer.size() < WINDOW_SIZE) {
            return {};
        }

        std::vector<float> results;

        // Process complete windows
        while (sample_buffer.size() >= WINDOW_SIZE) {
            // Extract current window
            std::vector<float> window(sample_buffer.begin(), sample_buffer.begin() + WINDOW_SIZE);

            // Apply Goertzel algorithm for mark tone detection
            float mark_magnitude = 0.0f;
            float mark_s1 = 0.0f;
            float mark_s2 = 0.0f;

            for (int i = WINDOW_SIZE - 1; i >= 0; i--) {
                float s0 = window[i] + MARK_COEF * mark_s1 - mark_s2;
                mark_s2 = mark_s1;
                mark_s1 = s0;
            }

            // Calculate magnitude
            mark_magnitude = sqrtf(mark_s1 * mark_s1 + mark_s2 * mark_s2 - MARK_COEF * mark_s1 * mark_s2);

            // Apply Goertzel algorithm for space tone detection
            float space_magnitude = 0.0f;
            float space_s1 = 0.0f;
            float space_s2 = 0.0f;

            for (int i = WINDOW_SIZE - 1; i >= 0; i--) {
                float s0 = window[i] + SPACE_COEF * space_s1 - space_s2;
                space_s2 = space_s1;
                space_s1 = s0;
            }

            // Calculate magnitude
            space_magnitude = sqrtf(space_s1 * space_s1 + space_s2 * space_s2 - SPACE_COEF * space_s1 * space_s2);

            // Normalize magnitudes
            float mark_normalized = mark_magnitude / WINDOW_SIZE;
            float space_normalized = space_magnitude / WINDOW_SIZE;

            // Calculate probability (simplified approach)
            float mark_prob = std::min(1.0f, mark_normalized / 1000.0f);
            float space_prob = std::min(1.0f, space_normalized / 1000.0f);

            // Determine which tone is stronger
            float probability = (mark_prob > space_prob) ? mark_prob : space_prob;

            results.push_back(probability);

            // Remove processed samples
            sample_buffer.erase(sample_buffer.begin(), sample_buffer.begin() + WINDOW_SIZE);
        }

        return results;
    }

