    void ProcessProbabilityData(const std::vector<float>& probabilities, float threshold)
    {
        // Process each probability value
        for (float prob : probabilities) {
            // Convert probability to binary bit (0 or 1) based on threshold
            uint8_t bit = (prob > threshold) ? 1 : 0;

            // Shift bit into buffer
            rx_buffer_ = (rx_buffer_ << 1) | bit;
            rx_bit_count_++;

            // Check if we have accumulated enough bits for a byte
            if (rx_bit_count_ >= 8) {
                uint8_t byte = (rx_buffer_ >> (rx_bit_count_ - 8)) & 0xFF;

                // Check for transmission state changes
                if (rx_state_ == RX_STATE_INACTIVE) {
                    // Look for start identifier
                    if (byte == START_IDENTIFIER) {
                        rx_state_ = RX_STATE_WAITING;
                        rx_byte_count_ = 0;
                        ESP_LOGI(kLogTag, "Start identifier detected");
                    }
                } else if (rx_state_ == RX_STATE_WAITING) {
                    // Wait for data to start flowing
                    if (byte != 0x00) {  // Non-zero byte indicates data start
                        rx_state_ = RX_STATE_RECEIVING;
                        rx_data_[rx_byte_count_] = byte;
                        rx_byte_count_++;
                        ESP_LOGI(kLogTag, "Started receiving data");
                    }
                } else if (rx_state_ == RX_STATE_RECEIVING) {
                    // Store received byte
                    rx_data_[rx_byte_count_] = byte;
                    rx_byte_count_++;

                    // Check if we've received complete packet
                    if (rx_byte_count_ >= MAX_PACKET_SIZE) {
                        // Validate checksum if needed
                        bool valid_checksum = true;
                        if (enable_checksum_) {
                            valid_checksum = ValidateChecksum(rx_data_, rx_byte_count_);
                        }

                        if (valid_checksum) {
                            // Process received data
                            HandleReceivedData(rx_data_, rx_byte_count_);
                            ESP_LOGI(kLogTag, "Data received successfully, %d bytes", rx_byte_count_);
                        } else {
                            ESP_LOGW(kLogTag, "Invalid checksum, discarding data");
                        }

                        // Reset for next transmission
                        rx_state_ = RX_STATE_INACTIVE;
                        rx_byte_count_ = 0;
                    }
                }

                // Reset bit counter for next byte
                rx_bit_count_ = 0;
            }
        }

        // Check for end identifier
        if (rx_state_ == RX_STATE_RECEIVING) {
            // Look for end identifier in recent bytes
            if (rx_byte_count_ >= 2) {
                uint8_t last_byte = rx_data_[rx_byte_count_ - 1];
                uint8_t second_last_byte = rx_data_[rx_byte_count_ - 2];

                if (last_byte == END_IDENTIFIER || 
                    (second_last_byte == END_IDENTIFIER && last_byte == 0x00)) {
                    // End of transmission detected
                    ESP_LOGI(kLogTag, "End identifier detected");

                    // Validate and process final packet
                    bool valid_checksum = true;
                    if (enable_checksum_) {
                        valid_checksum = ValidateChecksum(rx_data_, rx_byte_count_);
                    }

                    if (valid_checksum) {
                        HandleReceivedData(rx_data_, rx_byte_count_);
                        ESP_LOGI(kLogTag, "Complete data received, %d bytes", rx_byte_count_);
                    } else {
                        ESP_LOGW(kLogTag, "Invalid checksum on final packet");
                    }

                    rx_state_ = RX_STATE_INACTIVE;
                    rx_byte_count_ = 0;
                }
            }
        }
    }

cpp
std::vector<uint8_t> ConvertBitsToBytes(const std::vector<uint8_t>& bits) const
{
    std::vector<uint8_t> result;

    if (bits.empty()) {
        return result;
    }

    // Calculate how many complete bytes we can form
    size_t num_complete_bytes = bits.size() / 8;

    // Process each complete group of 8 bits
    for (size_t i = 0; i < num_complete_bytes; ++i) {
        uint8_t byte = 0;
        // Pack 8 bits into one byte
        for (int bit_pos = 0; bit_pos < 8; ++bit_pos) {
            if (bits[i * 8 + bit_pos] == 1) {
                byte |= (1 << (7 - bit_pos));  // MSB first ordering
            }
        }
        result.push_back(byte);
    }

    return result;
}

