void Backlight::RestoreBrightness()
{
    // Get brightness from settings
    uint8_t brightness = Settings::GetDisplayBrightness();

    // If brightness is zero or invalid, use minimum brightness
    if (brightness == 0) {
        brightness = 10;
    }

    // Calculate duty cycle (assuming 10-bit resolution with 1023 max)
    uint32_t duty_cycle = (1023 * brightness) / 100;

    // Apply the brightness to LEDC channel
    ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, duty_cycle);

    ESP_LOGD(TAG, "Restored backlight brightness: %d%%", brightness);
}

void Backlight::SetBrightness(uint8_t brightness, bool save_to_nvs)
{
    // Clamp brightness to valid range
    if (brightness > 100) {
        brightness = 100;
    }

    // Calculate duty cycle for LEDC (10-bit resolution)
    uint32_t duty_cycle = (1023 * brightness) / 100;

    // Set the LEDC duty cycle
    ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, duty_cycle);
    ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);

    // Optionally save to non-volatile storage
    if (save_to_nvs) {
        settings_save_backlight_brightness(brightness);
    }
}

void Backlight::OnTransitionTimer()
{
    // Check if we've reached the target brightness
    if (current_brightness == target_brightness) {
        // Stop the transition timer
        if (transition_timer != nullptr) {
            timer_stop(transition_timer);
        }
        return;
    }

    // Calculate the step size for smooth transition
    int brightness_step = (target_brightness > current_brightness) ? 1 : -1;

    // Update current brightness
    current_brightness += brightness_step;

    // Ensure brightness stays within valid range
    if (current_brightness < 0) {
        current_brightness = 0;
    } else if (current_brightness > 100) {
        current_brightness = 100;
    }

    // Set the new duty cycle
    uint32_t duty_cycle = (1023 * current_brightness) / 100;
    ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, duty_cycle);
    ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);

    // If we've reached the target, stop the timer
    if (current_brightness == target_brightness) {
        if (transition_timer != nullptr) {
            timer_stop(transition_timer);
        }
    }
}

