Board::Board() {
    ESP_LOGI(TAG, "Initializing board hardware...");

    // Initialize system information
    system_info_init();

    // Try to load existing UUID from NVS storage
    char uuid[37]; // UUID string format: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
    size_t uuid_len = sizeof(uuid);

    esp_err_t err = nvs_get_str(nvs_handle, "device_uuid", uuid, &uuid_len);

    if (err == ESP_OK && uuid_len > 0) {
        // UUID already exists, use it
        ESP_LOGI(TAG, "Loaded existing UUID: %s", uuid);
        strncpy(device_uuid, uuid, sizeof(device_uuid) - 1);
        device_uuid[sizeof(device_uuid) - 1] = '\0';
    } else {
        // Generate new UUID
        ESP_LOGI(TAG, "Generating new UUID...");
        generate_uuid(device_uuid);

        // Save UUID to NVS storage
        err = nvs_set_str(nvs_handle, "device_uuid", device_uuid);
        if (err == ESP_OK) {
            err = nvs_commit(nvs_handle);
            if (err == ESP_OK) {
                ESP_LOGI(TAG, "Saved new UUID: %s", device_uuid);
            } else {
                ESP_LOGE(TAG, "Failed to commit UUID to NVS");
            }
        } else {
            ESP_LOGE(TAG, "Failed to save UUID to NVS");
        }
    }

    // Initialize display subsystem
    display_init();

    // Initialize OLED display if available
    oled_display_init();

    // Load language configuration
    lang_config_load();

    // Initialize settings
    settings_init();

    ESP_LOGI(TAG, "Board initialization completed successfully");
}

// Helper function to generate UUID (simplified version)
void Board::generate_uuid(char* uuid_buffer) {
    // Generate random 128-bit UUID
    uint32_t random_data[4];
    random_data[0] = esp_random();
    random_data[1] = esp_random();
    random_data[2] = esp_random();
    random_data[3] = esp_random();

    // Format as UUID string (simplified)
    snprintf(uuid_buffer, 37, "%08x-%04x-%04x-%04x-%08x%04x",
             random_data[0], 
             (random_data[1] >> 16) & 0xFFFF,
             random_data[1] & 0xFFFF,
             (random_data[2] >> 16) & 0xFFFF,
             random_data[2] & 0xFFFF,
             random_data[3]);
}

std::string Board::GenerateUuid() {
    // Generate 16 bytes of random data
    uint8_t uuid[16];

    // Fill with random data from ESP32 hardware RNG
    for (int i = 0; i < 16; i++) {
        uuid[i] = (uint8_t)esp_random();
    }

    // Set version bits (4 bits) - version 4
    uuid[6] = (uuid[6] & 0x0f) | 0x40;

    // Set variant bits (2 bits) - RFC 4122 variant
    uuid[8] = (uuid[8] & 0x3f) | 0x80;

    // Format as string with hyphens
    char uuid_str[37]; // 36 chars + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

