std::string Board::GetSystemInfoJson() {
    cJSON *root = cJSON_CreateObject();

    // Hardware information
    cJSON *hardware = cJSON_CreateObject();
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    // Chip model name
    const char* chip_model = "unknown";
    switch (chip_info.model) {
        case CHIP_ESP32:
            chip_model = "ESP32";
            break;
        case CHIP_ESP32S2:
            chip_model = "ESP32-S2";
            break;
        case CHIP_ESP32S3:
            chip_model = "ESP32-S3";
            break;
        case CHIP_ESP32C3:
            chip_model = "ESP32-C3";
            break;
        default:
            chip_model = "Unknown";
            break;
    }

    cJSON_AddStringToObject(hardware, "chip_model", chip_model);
    cJSON_AddNumberToObject(hardware, "cores", chip_info.cores);
    cJSON_AddNumberToObject(hardware, "revision", chip_info.revision);

    // Flash size
    size_t flash_size = 0;
    esp_flash_get_size(NULL, &flash_size);
    cJSON_AddNumberToObject(hardware, "flash_size_bytes", flash_size);

    // MAC address
    uint8_t mac[6];
    esp_efuse_mac_get_default(mac);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02x:%02x:%02x:%02x:%02x:%02x",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    cJSON_AddStringToObject(hardware, "mac_address", mac_str);

    cJSON_AddItemToObject(root, "hardware", hardware);

    // Application metadata
    cJSON *app_metadata = cJSON_CreateObject();
    cJSON_AddStringToObject(app_metadata, "name", APP_NAME);
    cJSON_AddStringToObject(app_metadata, "version", APP_VERSION);
    cJSON_AddStringToObject(app_metadata, "compile_time", __DATE__ " " __TIME__);

    // Get OTA partition info
    const esp_partition_t *running = esp_ota_get_running_partition();
    if (running) {
        cJSON_AddStringToObject(app_metadata, "partition_label", running->label);
        cJSON_AddNumberToObject(app_metadata, "partition_addr", running->address);
        cJSON_AddNumberToObject(app_metadata, "partition_size", running->size);
    }

    cJSON_AddItemToObject(root, "application", app_metadata);

    // Runtime information
    cJSON *runtime = cJSON_CreateObject();
    cJSON_AddNumberToObject(runtime, "min_free_heap_size", esp_get_minimum_free_heap_size());
    cJSON_AddNumberToObject(runtime, "current_free_heap_size", esp_get_free_heap_size());
    cJSON_AddNumberToObject(runtime, "uptime_ms", esp_timer_get_time() / 1000);

    // Generate UUID (simple approach using random numbers)
    uint32_t uuid_low = esp_random();
    uint32_t uuid_high = esp_random();
    char uuid_str[37];
    snprintf(uuid_str, sizeof(uuid_str), "%08x-%08x-%08x-%08x",
             uuid_low, uuid_high, esp_random(), esp_random());
    cJSON_AddStringToObject(runtime, "uuid", uuid_str);

    cJSON_AddItemToObject(root, "runtime", runtime);

    // Partition table information
    cJSON *partitions = cJSON_CreateArray();
    const esp_partition_t *part = NULL;
    while ((part = esp_partition_find_first(ESP_PARTITION_TYPE_APP, ESP_PARTITION_SUBTYPE_ANY, NULL)) != NULL) {
        cJSON *partition_info = cJSON_CreateObject();
        cJSON_AddStringToObject(partition_info, "label", part->label);
        cJSON_AddNumberToObject(partition_info, "type", part->type);
        cJSON_AddNumberToObject(partition_info, "subtype", part->subtype);
        cJSON_AddNumberToObject(partition_info, "address", part->address);
        cJSON_AddNumberToObject(partition_info, "size", part->size);
        cJSON_AddItemToArray(partitions, partition_info);
        part = esp_partition_find_next(part);
    }
    cJSON_AddItemToObject(root, "partitions", partitions);

    // System information from settings
    cJSON *system_info = cJSON_CreateObject();
    cJSON_AddStringToObject(system_info, "firmware_version", FIRMWARE_VERSION);
    cJSON_AddStringToObject(system_info, "build_date", BUILD_DATE);
    cJSON_AddItemToObject(root, "system", system_info);

    // Convert to string
    char *json_string = cJSON_Print(root);
    std::string result = json_string;

    // Clean up
    cJSON_Delete(root);
    free(json_string);

    return result;
}

