I2cDevice::I2cDevice(i2c_master_bus_handle_t i2c_bus, uint8_t addr)
{
    // Store the bus handle and address
    this->i2c_bus = i2c_bus;
    this->addr = addr;

    // Configure I2C device settings
    i2c_device_config_t conf = {
        .dev_addr_len = I2C_ADDR_BIT_LEN_7,
        .device_address = addr,
        .scl_speed_hz = 100000,  // Standard I2C speed
    };

    // Register the device with the I2C master bus
    esp_err_t ret = i2c_master_bus_add_device(i2c_bus, &conf, &this->device_handle);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to add I2C device: %s", esp_err_to_name(ret));
        assert(0);  // Assert on failure
    }

    // Verify that device handle is valid
    assert(this->device_handle != NULL);
}

bool I2cDevice::WriteReg(uint8_t reg_addr, uint8_t reg_data)
{
    uint8_t buffer[2];
    buffer[0] = reg_addr;
    buffer[1] = reg_data;

    esp_err_t ret = i2c_master_transmit(this->i2c_bus, buffer, 2, 100 / portTICK_PERIOD_MS);

    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to write to I2C device at address 0x%02X, register 0x%02X", this->addr, reg_addr);
        return false;
    }

    return true;
}

uint8_t I2cDevice::ReadReg(uint8_t reg_addr)
{
    uint8_t data;
    esp_err_t ret = i2c_master_write_read_device(
        i2c_bus,           // I2C bus handle
        addr,              // Device address
        &reg_addr,         // Register address to write
        1,                 // Number of bytes to write
        &data,             // Buffer to read into
        1,                 // Number of bytes to read
        pdMS_TO_TICKS(100) // Timeout
    );

    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read register 0x%02X: %s", reg_addr, esp_err_to_name(ret));
        return 0; // Return 0 on error
    }

    return data;
}

