void WifiBoard::StartNetwork()
{
    // Initialize WiFi manager with predefined SSID prefix and language
    WifiManager::GetInstance().Init(CONFIG_WIFI_SSID_PREFIX, LANG_EN);

    // Set up unified event callback to handle various WiFi events
    WifiManager::GetInstance().SetEventCallback([](WifiManagerEvent_t event, void *data) {
        switch (event) {
            case WIFI_MANAGER_EVENT_SCAN_STARTED:
                ESP_LOGI(TAG, "WiFi scan started");
                break;

            case WIFI_MANAGER_EVENT_SCAN_COMPLETE:
                ESP_LOGI(TAG, "WiFi scan complete");
                break;

            case WIFI_MANAGER_EVENT_CONNECTING:
                ESP_LOGI(TAG, "Attempting to connect to WiFi");
                break;

            case WIFI_MANAGER_EVENT_CONNECTED:
                ESP_LOGI(TAG, "Successfully connected to WiFi");
                // Stop any ongoing configuration mode
                WifiManager::GetInstance().StopConfigMode();
                break;

            case WIFI_MANAGER_EVENT_DISCONNECTED:
                ESP_LOGI(TAG, "WiFi disconnected");
                // Attempt to reconnect or enter config mode
                break;

            case WIFI_MANAGER_EVENT_CONFIG_MODE_ENTER:
                ESP_LOGI(TAG, "Entering WiFi configuration mode");
                // Handle config mode entry
                break;

            case WIFI_MANAGER_EVENT_CONFIG_MODE_EXIT:
                ESP_LOGI(TAG, "Exiting WiFi configuration mode");
                // Handle config mode exit
                break;

            default:
                ESP_LOGW(TAG, "Unknown WiFi event: %d", event);
                break;
        }
    });

    // Attempt to establish WiFi connection
    bool connected = WifiManager::GetInstance().Connect();

    if (!connected) {
        ESP_LOGW(TAG, "Failed to connect to WiFi, entering config mode");
        // Enter configuration mode if connection fails
        WifiManager::GetInstance().StartConfigMode();
    }
}

void WifiBoard::TryWifiConnect() {
    ESP_LOGI(TAG, "Attempting to connect to WiFi...");

    // Check if we have any saved SSIDs
    auto &ssid_manager = SsidManager::GetInstance();
    if (ssid_manager.GetNumSavedSsids() == 0) {
        ESP_LOGW(TAG, "No saved SSIDs found, starting WiFi config mode");
        // Brief delay before starting config mode
        vTaskDelay(pdMS_TO_TICKS(1000));
        StartWifiConfigMode();
        return;
    }

    // Attempt to connect to WiFi
    auto &wifi = WifiManager::GetInstance();
    bool connected = false;

    // Set up connection timeout
    TickType_t start_time = xTaskGetTickCount();
    const TickType_t timeout_ticks = pdMS_TO_TICKS(CONNECT_TIMEOUT_SEC * 1000);

    while (!connected && (xTaskGetTickCount() - start_time) < timeout_ticks) {
        // Try to connect to the first available SSID
        auto ssid = ssid_manager.GetNextSsid();
        if (!ssid.empty()) {
            ESP_LOGI(TAG, "Connecting to SSID: %s", ssid.c_str());

            // Stop any existing station connection
            wifi.StopStation();

            // Configure and start station with the saved SSID
            wifi.SetStationConfig(ssid, ssid_manager.GetPasswordForSsid(ssid));
            wifi.StartStation();

            // Wait for connection or timeout
            int wait_count = 0;
            while (wait_count < 10) {  // Wait up to 10 seconds
                if (wifi.IsStationConnected()) {
                    connected = true;
                    break;
                }
                vTaskDelay(pdMS_TO_TICKS(1000));
                wait_count++;
            }

            if (connected) {
                ESP_LOGI(TAG, "Successfully connected to WiFi");
                break;
            } else {
                ESP_LOGW(TAG, "Failed to connect to SSID: %s", ssid.c_str());
                // Try next SSID if available
                ssid_manager.MoveNextSsid();
            }
        } else {
            break;  // No more SSIDs to try
        }
    }

    if (!connected) {
        ESP_LOGW(TAG, "WiFi connection timeout, entering config mode");
        wifi.StopStation();
        StartWifiConfigMode();
    }
}

void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string &data) {
    switch (event) {
        case NetworkEvent::CONNECTED: {
            // Clear configuration mode flag
            config_mode_ = false;

            // Stop any active provisioning
            if (provisioning_active_) {
                provisioning_active_ = false;
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
                Blufi::GetInstance().StopProvisioning();
#endif
            }

            // Cancel connection timeout timer
            if (connect_timer_handle_ != nullptr) {
                xTimerDelete(connect_timer_handle_, 0);
                connect_timer_handle_ = nullptr;
            }

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, data);
            }

            break;
        }

        case NetworkEvent::DISCONNECTED: {
            // Reset connection state
            connected_ = false;

            // Cancel connection timeout timer
            if (connect_timer_handle_ != nullptr) {
                xTimerDelete(connect_timer_handle_, 0);
                connect_timer_handle_ = nullptr;
            }

            // Restart connection attempt after delay
            if (!config_mode_) {
                // Schedule reconnection attempt
                xTimerChangePeriod(reconnect_timer_handle_, pdMS_TO_TICKS(5000), 0);
                xTimerStart(reconnect_timer_handle_, 0);
            }

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, data);
            }

            break;
        }

        case NetworkEvent::SCAN_COMPLETE: {
            // Handle scan results
            if (network_callback_) {
                network_callback_(event, data);
            }
            break;
        }

        case NetworkEvent::CONFIG_MODE_ENTERED: {
            // Set configuration mode flag
            config_mode_ = true;

            // Stop station if running
            WifiManager::GetInstance().StopStation();

            // Cancel any pending connection attempts
            if (connect_timer_handle_ != nullptr) {
                xTimerDelete(connect_timer_handle_, 0);
                connect_timer_handle_ = nullptr;
            }

            // Start configuration mode
            StartWifiConfigMode();

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, data);
            }

            break;
        }

        case NetworkEvent::CONFIG_MODE_EXITED: {
            // Clear configuration mode flag
            config_mode_ = false;

            // Cancel connection timeout timer
            if (connect_timer_handle_ != nullptr) {
                xTimerDelete(connect_timer_handle_, 0);
                connect_timer_handle_ = nullptr;
            }

            // Restart station
            WifiManager::GetInstance().StartStation();

            // Schedule reconnection attempt
            xTimerChangePeriod(reconnect_timer_handle_, pdMS_TO_TICKS(1000), 0);
            xTimerStart(reconnect_timer_handle_, 0);

            // Notify external callback if set
            if (network_callback_) {
                network_callback_(event, data);
            }

            break;
        }

        default:
            break;
    }
}

