void WifiBoard::StartWifiConfigMode() {
    // Set board state to configuring mode
    Board::GetInstance().SetState(BoardState::CONFIGURING);

    // Get display for user feedback
    auto disp = Board::GetInstance().GetDisplay();

    // Show configuration mode prompt
    if (disp) {
        disp->Clear();
        disp->DrawStringCentered("WiFi Config Mode", 10);
        disp->DrawStringCentered("Touch to configure", 30);
        disp->Update();
    }

    // Start Wi-Fi station
    WifiManager::GetInstance().StartStation();

    // Configure timeout task for WiFi connection
    xTaskCreate([](void *arg) {
        auto *board = static_cast<WifiBoard *>(arg);
        ESP_LOGW(TAG, "WiFi connection timeout, entering config mode");

        // Stop current station connection
        WifiManager::GetInstance().StopStation();

        // Get necessary components
        auto &wifi = WifiManager::GetInstance();
        auto disp = Board::GetInstance().GetDisplay();

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
        // Use BLUFI for BLE provisioning
        ESP_LOGI(TAG, "Starting BLUFI provisioning");
        Blufi::StartProvisioning(disp);
#elif defined(CONFIG_USE_AUDIO_WIFI_PROVISIONING)
        // Use audio provisioning
        ESP_LOGI(TAG, "Starting audio provisioning");
        // Note: 'ch' and 'app' variables seem to be missing from context
        // This would need to be properly initialized in actual implementation
        audio_wifi_config::ReceiveWifiCredentialsFromAudio(nullptr, &wifi, disp, nullptr);
#else
        // Default to hotspot provisioning
        ESP_LOGI(TAG, "Starting hotspot provisioning");
        // Enable hotspot mode
        WifiManager::GetInstance().StartSoftAP();
        // Show hotspot credentials on display
        if (disp) {
            disp->Clear();
            disp->DrawStringCentered("Hotspot Active", 10);
            disp->DrawStringCentered("SSID: " + WifiManager::GetInstance().GetSoftAPSSID(), 30);
            disp->DrawStringCentered("Password: " + WifiManager::GetInstance().GetSoftAPPass(), 50);
            disp->Update();
        }
#endif

        // Clean up and delete this task
        vTaskDelete(NULL);
    }, "wifi_config_timeout", 4096, this, 5, NULL);

    // Start connection attempt with timeout
    WifiManager::GetInstance().ConnectToNetwork(CONNECT_TIMEOUT_SEC);
}

void WifiBoard::EnterWifiConfigMode() {
    // Wait for the board version to be shown
    vTaskDelay(pdMS_TO_TICKS(1500));

    // Stop the WiFi station
    WifiManager::GetInstance().StopStation();

    // Get display instance
    auto disp = Board::GetInstance().GetDisplay();

    // Receive WiFi credentials from audio
    auto &wifi = WifiManager::GetInstance();
    audio_wifi_config::ReceiveWifiCredentialsFromAudio(&app, &wifi, disp, ch);

    // Delete the current task
    vTaskDelete(NULL);
}

