NetworkInterface* WifiBoard::GetNetwork() {
    static NetworkInterface* network_instance = nullptr;

    if (network_instance == nullptr) {
        // Initialize the network interface if it hasn't been created yet
        network_instance = new NetworkInterface();

        // Configure network settings
        network_instance->SetTimeout(CONNECT_TIMEOUT_SEC);

