std::string WifiBoard::GetNetworkStateIcon() {
    // Check if we're in configuration mode
    if (WifiManager::GetInstance().IsConfigMode()) {
        return ICON_WIFI_CONFIG;
    }

    // Check connection status
    auto wifi_status = WifiManager::GetInstance().GetConnectionStatus();

    switch (wifi_status) {
        case WifiConnectionStatus::DISCONNECTED:
            return ICON_WIFI_DISCONNECTED;

        case WifiConnectionStatus::CONNECTED: {
            // Get signal strength
            int rssi = WifiManager::GetInstance().GetSignalStrength();

            // Determine signal quality based on RSSI values
            if (rssi >= -50) {
                // Strong signal
                return ICON_WIFI_STRENGTH_4;
            } else if (rssi >= -70) {
                // Fair signal
                return ICON_WIFI_STRENGTH_3;
            } else if (rssi >= -80) {
                // Weak signal
                return ICON_WIFI_STRENGTH_2;
            } else {
                // Very weak signal
                return ICON_WIFI_STRENGTH_1;
            }
        }

        default:
            return ICON_WIFI_UNKNOWN;
    }
}

