std::string WifiBoard::GetBoardJson()
{
    cJSON *root = cJSON_CreateObject();
    if (root == nullptr) {
        return "";
    }

    // Add board type
    cJSON_AddStringToObject(root, "type", "wifi_board");

    // Add board name
    cJSON_AddStringToObject(root, "name", "ESP32 WiFi Board");

    // Add MAC address
    cJSON_AddStringToObject(root, "mac", SystemInfo::GetMacAddress().c_str());

    // Check if we're in configuration mode
    bool in_config_mode = WifiManager::GetInstance().IsApActive() || 
                         WifiManager::GetInstance().IsStationActive();

    // If not in config mode, add Wi-Fi information
    if (!in_config_mode) {
        // Add SSID if connected
        std::string ssid = WifiManager::GetInstance().GetConnectedSsid();
        if (!ssid.empty()) {
            cJSON_AddStringToObject(root, "ssid", ssid.c_str());
        }

        // Add RSSI if available
        int rssi = WifiManager::GetInstance().GetRssi();
        if (rssi != 0) {
            cJSON_AddNumberToObject(root, "rssi", rssi);
        }

        // Add channel if available
        int channel = WifiManager::GetInstance().GetChannel();
        if (channel > 0) {
            cJSON_AddNumberToObject(root, "channel", channel);
        }

        // Add IP address if available
        std::string ip = WifiManager::GetInstance().GetIpAddress();
        if (!ip.empty()) {
            cJSON_AddStringToObject(root, "ip", ip.c_str());
        }
    }

    // Convert to string
    char *str = cJSON_PrintUnformatted(root);
    std::string result(str);
    cJSON_free(str);
    cJSON_Delete(root);

    return result;
}

void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level)
{
    wifi_ps_type_t wifi_power_save_level;

    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            wifi_power_save_level = WIFI_PS_MIN_MODEM;
            break;
        case PowerSaveLevel::BALANCED:
            wifi_power_save_level = WIFI_PS_MAX_MODEM;
            break;
        case PowerSaveLevel::PERFORMANCE:
            wifi_power_save_level = WIFI_PS_NONE;
