std::string WifiBoard::GetDeviceStatusJson() {
    cJSON *root = cJSON_CreateObject();

    // Add audio speaker volume
    int volume = Audio::GetInstance().GetVolume();
    cJSON_AddNumberToObject(root, "volume", volume);

    // Add screen brightness and theme
    auto display = Board::GetInstance().GetDisplay();
    int brightness = display->GetBrightness();
    cJSON_AddNumberToObject(root, "brightness", brightness);

    // Add theme (assuming it's stored as a string)
    std::string theme = Settings::GetInstance().GetTheme();
    cJSON_AddStringToObject(root, "theme", theme.c_str());

    // Add battery level and charging state
    auto power = PowerManager::GetInstance();
    int battery_level = power->GetBatteryLevel();
    bool is_charging = power->IsCharging();
    cJSON_AddNumberToObject(root, "battery", battery_level);
    cJSON_AddBoolToObject(root, "charging", is_charging);

    // Add WiFi network details (SSID and signal strength)
    auto wifi_manager = WifiManager::GetInstance();
    std::string ssid = wifi_manager.GetConnectedSsid();
    int rssi = wifi_manager.GetSignalStrength();
    cJSON_AddStringToObject(root, "ssid", ssid.c_str());
    cJSON_AddNumberToObject(root, "rssi", rssi);

    // Add chip temperature
    float temperature = SystemInfo::GetChipTemperature();
    cJSON_AddNumberToObject(root, "temperature", temperature);

    // Add MAC address
    std::string mac_address = SystemInfo::GetMacAddress();
    cJSON_AddStringToObject(root, "mac", mac_address.c_str());

    // Add device uptime
    uint32_t uptime = xTaskGetTickCount() / configTICK_RATE_HZ;
    cJSON_AddNumberToObject(root, "uptime", uptime);

    // Add firmware version
    std::string firmware_version = SystemInfo::GetFirmwareVersion();
    cJSON_AddStringToObject(root, "firmware", firmware_version.c_str());

    // Add WiFi provisioning status
    bool is_provisioned = wifi_manager.IsProvisioned();
    cJSON_AddBoolToObject(root, "provisioned", is_provisioned);

    // Add current WiFi mode
    std::string wifi_mode = wifi_manager.GetModeString();
    cJSON_AddStringToObject(root, "wifi_mode", wifi_mode.c_str());

    // Add memory info
    HeapStats stats = esp_get_heap_stats();
    cJSON_AddNumberToObject(root, "free_heap", stats.free_size);
    cJSON_AddNumberToObject(root, "max_alloc", stats.largest_free_block);

    // Generate JSON string
    char *str = cJSON_PrintUnformatted(root);
    std::string result(str);
    cJSON_free(str);
    cJSON_Delete(root);

    return result;
}

