    rmt_tx.channel = RMT_CHANNEL_0;
    rmt_tx.gpio_num = gpio;
    rmt_tx.mem_block_num = 1;
    rmt_tx.clk_div = 2;  // 40MHz / 2 = 20MHz counter clock
    rmt_tx.tx_config.loop_en = false;
    rmt_tx.tx_config.idle_output_en = true;
    rmt_tx.tx_config.idle_level = RMT_IDLE_LEVEL_LOW;
    rmt_tx.tx_config.carrier_en = false;
    rmt_tx.tx_config.mod = true;
    rmt_tx.tx_config.carrier_freq_hz = 0;
    rmt_tx.tx_config.carrier_duty_percent = 50;
    rmt_tx.tx_config.carrier_level = RMT_CARRIER_LEVEL_LOW;
    rmt_tx.rmt_mode = RMT_MODE_TX;

    // Configure RMT for WS2812 timing
    ESP_ERROR_CHECK(rmt_config(&rmt_tx));
    ESP_ERROR_CHECK(rmt_driver_install(rmt_tx.channel, 0, 0));

    // Initialize LED state
    this->brightness = DEFAULT_BRIGHTNESS;
    this->is_blinking = false;
    this->blink_count = 0;
    this->blink_period_ms = 0;

    // Clear LED initially (turn off)
    this->clear();
}

