void SingleLed::StartBlinkTask(int numBlinks, int intervalMs)
{
    // Check if LED strip is initialized
    if (!isInitialized) {
        ESP_LOGW(TAG, "LED strip not initialized, cannot start blink task");
        return;
    }

    // Store blink parameters
    this->numBlinks = numBlinks;
    this->intervalMs = intervalMs;
    this->blinkCount = 0;

    // Create and start the timer for blinking
    esp_timer_create_args_t timer_args = {
        .callback = &SingleLed::blinkTimerCallback,
        .arg = this,
        .name = "led_blink_timer"
    };

    esp_err_t err = esp_timer_create(&timer_args, &blinkTimer);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create blink timer: %s", esp_err_to_name(err));
        return;
    }

    // Start the timer with the specified interval
    err = esp_timer_start_periodic(blinkTimer, intervalMs * 1000); // Convert ms to microseconds
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start blink timer: %s", esp_err_to_name(err));
        return;
    }

    ESP_LOGI(TAG, "Started blink task with %d blinks, interval %d ms", numBlinks, intervalMs);
}

void SingleLed::OnBlinkTimer()
{
    // Acquire mutex for thread-safe access
    if (xSemaphoreTake(m_mutex, 0) == pdTRUE) {
        // Check if we're still blinking
        if (m_blinkCount != 0) {
            // Toggle the LED state
            m_isOn = !m_isOn;

            // Update GPIO state
            gpio_set_level(m_gpio, m_isOn ? 1 : 0);

            // Decrement blink count for finite blinks
            if (m_blinkCount > 0) {
                m_blinkCount--;
            }

            // If we've completed all blinks, stop the timer
            if (m_blinkCount == 0) {
                // Stop the timer
                if (m_timer) {
                    timer_stop(m_timer);
                }
            }
        } else {
            // For infinite blinking, just toggle and continue
            m_isOn = !m_isOn;
            gpio_set_level(m_gpio, m_isOn ? 1 : 0);
        }

        // Release mutex
        xSemaphoreGive(m_mutex);
    }
}

void SingleLed::OnStateChanged(DeviceState state)
{
    // Stop any ongoing blink pattern
    if (blink_timer != nullptr) {
        timer_stop(blink_timer);
        timer_delete(blink_timer);
        blink_timer = nullptr;
    }

    // Handle different device states
    switch (state) {
        case DEVICE_STATE_STARTING:
            // Blue solid light - system is starting up
            ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, HIGH_BRIGHTNESS);
            ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);
            break;

        case DEVICE_STATE_WIFI_CONFIG:
            // Yellow blinking - Wi-Fi configuration mode
            blink_pattern(BLINK_PATTERN_FAST, LOW_BRIGHTNESS);
            break;

        case DEVICE_STATE_IDLE:
            // Green solid light - system is idle and ready
            ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, HIGH_BRIGHTNESS);
            ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);
            break;

        case DEVICE_STATE_CONNECTING:
            // Blue blinking - connecting to network
            blink_pattern(BLINK_PATTERN_MEDIUM, DEFAULT_BRIGHTNESS);
            break;

        case DEVICE_STATE_LISTENING:
            // Cyan blinking - listening for voice input
            blink_pattern(BLINK_PATTERN_SLOW, DEFAULT_BRIGHTNESS);
            break;

        case DEVICE_STATE_SPEAKING:
            // White blinking - speaking/playing audio
            blink_pattern(BLINK_PATTERN_FAST, HIGH_BRIGHTNESS);
            break;

        case DEVICE_STATE_UPGRADING:
            // Purple blinking - firmware upgrade in progress
            blink_pattern(BLINK_PATTERN_VERY_FAST, LOW_BRIGHTNESS);
            break;

        case DEVICE_STATE_ACTIVATING:
            // Orange blinking - device activation in progress
            blink_pattern(BLINK_PATTERN_MEDIUM, DEFAULT_BRIGHTNESS);
            break;

        default:
            // Off by default for unknown states
            ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, 0);
            ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);
            break;
    }
}

// Helper function to set up blink patterns
void SingleLed::blink_pattern(int pattern_type, int brightness)
{
    // Configure timer for blinking
    timer_config_t config = {
        .alarm_en = TIMER_ALARM_EN,
        .counter_en = TIMER_PAUSE,
        .intr_type = TIMER_INTR_LEVEL,
        .counter_dir = TIMER_COUNT_UP,
        .auto_reload = TIMER_AUTORELOAD_EN,
        .divider = 80  // 80MHz / 80 = 1MHz clock
    };

    timer_init(TIMER_GROUP_0, TIMER_0, &config);
    timer_set_counter_value(TIMER_GROUP_0, TIMER_0, 0x00000000ULL);

    // Set alarm value based on pattern type
    uint64_t alarm_value;
    switch(pattern_type) {
        case BLINK_PATTERN_FAST:
            alarm_value = 100000;  // 100ms
            break;
        case BLINK_PATTERN_MEDIUM:
            alarm_value = 500000;  // 500ms
            break;
        case BLINK_PATTERN_SLOW:
            alarm_value = 1000000; // 1s
            break;
        case BLINK_PATTERN_VERY_FAST:
            alarm_value = 50000;   // 50ms
            break;
        default:
            alarm_value = 500000;  // Default 500ms
    }

    timer_set_alarm_value(TIMER_GROUP_0, TIMER_0, alarm_value);
    timer_enable_intr(TIMER_GROUP_0, TIMER_0);
    timer_start(TIMER_GROUP_0, TIMER_0);
}

MqttProtocol::MqttProtocol()
{
    // Initialize the MQTT protocol instance
    mqtt_client_ = nullptr;
    reconnect_timer_ = nullptr;
    session_id_ = "";

    // Create event group for synchronization
    event_group_ = xEventGroupCreate();
    if (event_group_ == NULL) {
        ESP_LOGE(TAG, "Failed to create event group");
        return;
    }

    // Create reconnect timer
    reconnect_timer_ = xTimerCreate(
        "mqtt_reconnect",
        pdMS_TO_TICKS(5000),  // 5 second period
        pdTRUE,               // Auto-reload
        this,
        MqttProtocol::ReconnectTimerCallback
    );

    if (reconnect_timer_ == NULL) {
        ESP_LOGE(TAG, "Failed to create reconnect timer");
        return;
    }

    // Initialize network interface
    auto network = Board::GetInstance().GetNetwork();
    if (network == nullptr) {
        ESP_LOGE(TAG, "Failed to get network interface");
        return;
    }

    // Set up MQTT client configuration
    mqtt_cfg_.broker.address.uri = settings_get_mqtt_broker_url();
    mqtt_cfg_.credentials.client_id = settings_get_device_id();
    mqtt_cfg_.credentials.username = settings_get_mqtt_username();
    mqtt_cfg_.credentials.password = settings_get_mqtt_password();
    mqtt_cfg_.session.last_will_topic = settings_get_will_topic();
    mqtt_cfg_.session.last_will_msg = "Device disconnected";
    mqtt_cfg_.session.last_will_qos = 1;
    mqtt_cfg_.session.last_will_retain = true;

    // Initialize MQTT client
    mqtt_client_ = esp_mqtt_client_init(&mqtt_cfg_);

    // Set up event handlers
    esp_mqtt_client_register_event(mqtt_client_, ESP_EVENT_ANY_ID, MqttEventHandler, this);

    // Start the reconnect timer
    xTimerStart(reconnect_timer_, 0);
}

MqttProtocol::~MqttProtocol()
{
    // Stop and delete the reconnect timer
    if (reconnect_timer_) {
        xTimerStop(reconnect_timer_, 0);
        xTimerDelete(reconnect_timer_, 0);
        reconnect_timer_ = nullptr;
    }

    // Reset UDP resources
    if (udp_socket_) {
        closesocket(udp_socket_);
        udp_socket_ = 0;
    }

    // Reset MQTT resources
    if (mqtt_client_) {
        esp_mqtt_client_stop(mqtt_client_);
        esp_mqtt_client_destroy(mqtt_client_);
        mqtt_client_ = nullptr;
    }

    // Release the event group
    if (event_group_) {
        vEventGroupDelete(event_group_);
        event_group_ = nullptr;
    }

    // Mark the instance as inactive
    is_active_ = false;
}

void MqttProtocol::StartMqttClient(bool force_reconnect)
{
    // Check if we're already connected and force_reconnect is not set
    if (is_connected_ && !force_reconnect) {
        ESP_LOGI(TAG, "MQTT client already connected");
        return;
    }

    // Get network instance
    auto network = Board::GetInstance().GetNetwork();
    if (!network) {
        ESP_LOGE(TAG, "Failed to get network instance");
        return;
    }

    // Get MQTT configuration from settings
    auto mqtt_config = Settings::GetInstance().GetMqttConfig();
    if (!mqtt_config) {
        ESP_LOGE(TAG, "Failed to get MQTT configuration");
        return;
    }

    // Initialize MQTT client if not already done
    if (!mqtt_client_) {
        mqtt_client_ = esp_mqtt_client_init(&mqtt_config->client_config);
        if (!mqtt_client_) {
            ESP_LOGE(TAG, "Failed to initialize MQTT client");
            return;
        }
    }

    // Set up MQTT event handlers
    esp_mqtt_client_register_event(mqtt_client_, ESP_EVENT_ANY_ID, mqtt_event_handler, this);

    // Connect to MQTT broker
    esp_err_t err = esp_mqtt_client_start(mqtt_client_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start MQTT client: %s", esp_err_to_name(err));

        // Schedule reconnection attempt
        if (reconnect_timer_) {
            xTimerStop(reconnect_timer_, 0);
            xTimerDelete(reconnect_timer_, 0);
        }
        reconnect_timer_ = xTimerCreate("mqtt_reconnect", pdMS_TO_TICKS(5000), pdTRUE, 
                                       this, mqtt_reconnect_timer_callback);
        if (reconnect_timer_) {
            xTimerStart(reconnect_timer_, 0);
        }
        return;
    }

    // Set connected flag
    is_connected_ = true;

    ESP_LOGI(TAG, "MQTT client started successfully");

    // Publish connection status message
    std::string status_msg = "{\"type\":\"connected\",\"device_id\":\"" + 
                            Settings::GetInstance().GetDeviceId() + "\"}";

    Publish(MQTT_STATUS_TOPIC, status_msg.c_str());
}

