bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    // Validate input
    if (!packet) {
        ESP_LOGE(TAG, "Invalid audio packet received");
        return false;
    }

    // Get network instance
    auto network = Board::GetInstance().GetNetwork();
    if (!network) {
        ESP_LOGE(TAG, "Failed to get network instance");
        return false;
    }

    // Get UDP channel
    auto udp_channel = network->GetUdpChannel();
    if (!udp_channel) {
        ESP_LOGE(TAG, "Failed to get UDP channel");
        return false;
    }

    // Thread-safe access to UDP channel
    std::lock_guard<std::mutex> lock(udp_mutex_);

    try {
        // Prepare encryption parameters
        uint8_t nonce[12];
        uint32_t timestamp = esp_timer_get_time() / 1000; // Convert to milliseconds

        // Create nonce from packet size, timestamp, and sequence number
        memcpy(nonce, &packet->size, 4);           // Packet size
        memcpy(nonce + 4, &timestamp, 4);          // Timestamp
        memcpy(nonce + 8, &packet->sequence_number, 4); // Sequence number

        // Encrypt the audio payload using AES-CTR mode
        std::vector<uint8_t> encrypted_data(packet->size);
        if (!AesCtrEncrypt(packet->data, packet->size, encrypted_data.data(), nonce)) {
            ESP_LOGE(TAG, "AES-CTR encryption failed");
            return false;
        }

        // Send encrypted data over UDP
        int result = udp_channel->SendTo(
            encrypted_data.data(),
            encrypted_data.size(),
            network->GetServerAddress(),
            network->GetServerPort()
        );

        if (result < 0) {
            ESP_LOGE(TAG, "UDP send failed with error: %d", result);
            return false;
        }

        ESP_LOGD(TAG, "Audio packet sent successfully, size: %d", packet->size);
        return true;
    }
    catch (const std::exception& e) {
        ESP_LOGE(TAG, "Exception in SendAudio: %s", e.what());
        return false;
    }
    catch (...) {
        ESP_LOGE(TAG, "Unknown exception in SendAudio");
        return false;
    }
}

void MqttProtocol::CloseAudioChannel()
{
    // Reset UDP connection
    auto network = Board::GetInstance().GetNetwork();
    if (network) {
        network->ResetUdpConnection();
    }

    // Create goodbye message
    std::string message = "{";
    message += "\"session_id\":\"" + session_id_ + "\",";
    message += "\"type\":\"goodbye\"";
    message += "}";

    // Send goodbye message to server
    if (network && !message.empty()) {
        network->SendUdpMessage(message);
    }

    // Trigger callback notification to application
    if (on_audio_channel_closed_) {
        on_audio_channel_closed_();
    }

    // Reset audio session parameters
    session_id_.clear();
    server_frame_duration_ = 0;
}

