void MqttProtocol::OpenAudioChannel()
{
    ESP_LOGI(TAG, "Opening audio channel");

    // Get network instance
    auto network = Board::GetInstance().GetNetwork();

    // Connect to MQTT broker
    if (!network->ConnectMqtt())
    {
        ESP_LOGE(TAG, "Failed to connect to MQTT broker");
        return;
    }

    // Prepare hello message
    std::string message = "{";
    message += "\"session_id\":\"" + session_id_ + "\",";
    message += "\"type\":\"hello\",";
    message += "\"audio_params\":{";
    message += "\"sample_rate\":" + std::to_string(audio_params_->sample_rate) + ",";
    message += "\"channels\":" + std::to_string(audio_params_->channels) + ",";
    message += "\"bitrate\":" + std::to_string(audio_params_->bitrate);
    message += "}";
    message += "}";

    // Send hello message
    if (!network->PublishMqtt("audio/hello", message))
    {
        ESP_LOGE(TAG, "Failed to send hello message");
        network->DisconnectMqtt();
        return;
    }

    // Wait for server response
    bool response_received = false;
    int timeout_count = 0;
    const int max_timeout = 10; // 10 seconds timeout

    while (!response_received && timeout_count < max_timeout)
    {
        // Check for incoming messages
        std::string response = network->ReceiveMqtt(1000); // 1 second timeout
        if (!response.empty())
        {
            // Parse response
            cJSON* root = cJSON_Parse(response.c_str());
            if (root != nullptr)
            {
                cJSON* type = cJSON_GetObjectItem(root, "type");
                if (cJSON_IsString(type) && strcmp(type->valuestring, "ack") == 0)
                {
                    response_received = true;

                    // Extract UDP connection parameters
                    cJSON* udp = cJSON_GetObjectItem(root, "udp");
                    if (udp != nullptr)
                    {
                        cJSON* ip = cJSON_GetObjectItem(udp, "ip");
                        cJSON* port = cJSON_GetObjectItem(udp, "port");

                        if (cJSON_IsString(ip) && cJSON_IsNumber(port))
                        {
                            std::string udp_ip = ip->valuestring;
                            int udp_port = port->valueint;

                            // Setup UDP connection
                            if (network->SetupUdpConnection(udp_ip, udp_port))
                            {
                                ESP_LOGI(TAG, "UDP connection established");

                                // Start receiving audio packets
                                StartAudioReception();
                            }
                            else
                            {
                                ESP_LOGE(TAG, "Failed to setup UDP connection");
                            }
                        }
                    }
                }
                cJSON_Delete(root);
            }
        }
        timeout_count++;
        vTaskDelay(1000 / portTICK_PERIOD_MS); // Wait 1 second
    }

    if (!response_received)
    {
        ESP_LOGE(TAG, "Timeout waiting for server acknowledgment");
        network->DisconnectMqtt();
    }
}

void MqttProtocol::StartAudioReception()
{
    ESP_LOGI(TAG, "Starting audio reception");

    auto network = Board::GetInstance().GetNetwork();

    // Main audio reception loop
    while (true)
    {
        // Receive UDP packet
        std::vector<uint8_t> packet_data = network->ReceiveUdpPacket();

        if (!packet_data.empty())
        {
            // Decrypt packet
            std::vector<uint8_t> decrypted_data = DecryptAudioPacket(packet_data);

            if (!decrypted_data.empty())
            {
                // Process audio data through callback
                if (audio_callback_)
                {
                    audio_callback_(decrypted_data.data(), decrypted_data.size());
                }
            }
            else
            {
                ESP_LOGW(TAG, "Failed to decrypt audio packet");
            }
        }

        // Small delay to prevent excessive CPU usage
        vTaskDelay(10 / portTICK_PERIOD_MS);
    }
}

