void MqttProtocol::ParseServerHello(const cJSON *root)
{
    // Parse UDP settings
    auto udp = cJSON_GetObjectItem(root, "udp");
    if (cJSON_IsObject(udp))
    {
        auto server_addr = cJSON_GetObjectItem(udp, "server_addr");
        if (cJSON_IsString(server_addr))
        {
            strncpy(server_address_, server_addr->valuestring, sizeof(server_address_) - 1);
            server_address_[sizeof(server_address_) - 1] = '\0';
        }

        auto server_port = cJSON_GetObjectItem(udp, "server_port");
        if (cJSON_IsNumber(server_port))
        {
            server_port_ = server_port->valueint;
        }

        auto encryption_key = cJSON_GetObjectItem(udp, "encryption_key");
        if (cJSON_IsString(encryption_key))
        {
            strncpy(encryption_key_, encryption_key->valuestring, sizeof(encryption_key_) - 1);
            encryption_key_[sizeof(encryption_key_) - 1] = '\0';
        }

        auto nonce = cJSON_GetObjectItem(udp, "nonce");
        if (cJSON_IsString(nonce))
        {
            strncpy(nonce_, nonce->valuestring, sizeof(nonce_) - 1);
            nonce_[sizeof(nonce_) - 1] = '\0';
        }
    }

    // Parse audio parameters
    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (cJSON_IsObject(audio_params))
    {
        auto sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (cJSON_IsNumber(sample_rate))
        {
            server_sample_rate_ = sample_rate->valueint;
        }

        auto frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (cJSON_IsNumber(frame_duration))
        {
            server_frame_duration_ = frame_duration->valueint;
        }
    }

    // Initialize AES encryption with the provided key and nonce
    // Assuming there's an AES initialization method available
    // aes_init(encryption_key_, nonce_);

    // Signal that server hello has been processed successfully
    server_hello_received_ = true;

    ESP_LOGI(TAG, "Server hello parsed successfully");
}

int CharToHex(char c)
{
    if (c >= '0' && c <= '9')
    {
        return c - '0';
    }
    else if (c >= 'A' && c <= 'F')
    {
        return c - 'A' + 10;
    }
    else if (c >= 'a' && c <= 'f')
    {
        return c - 'a' + 10;
    }
    else
    {
        return 0; // Return 0 for invalid input characters
    }
}

std::string MqttProtocol::DecodeHexString(const std::string &hex_string)
{
    std::string result;

    // Handle empty string
    if (hex_string.empty()) {
        return result;
    }

    // Process two characters at a time
    for (size_t i = 0; i < hex_string.length(); i += 2) {
        // Ensure we have at least two characters left
        if (i + 1 >= hex_string.length()) {
            // Invalid hex string - odd number of characters
            return result;
        }

        // Get two hex characters
        char hex_char1 = hex_string[i];
        char hex_char2 = hex_string[i + 1];

        // Convert hex characters to decimal values
        int val1 = 0, val2 = 0;

        // Convert first hex character
        if (hex_char1 >= '0' && hex_char1 <= '9') {
            val1 = hex_char1 - '0';
        } else if (hex_char1 >= 'a' && hex_char1 <= 'f') {
            val1 = hex_char1 - 'a' + 10;
        } else if (hex_char1 >= 'A' && hex_char1 <= 'F') {
            val1 = hex_char1 - 'A' + 10;
        } else {
            // Invalid hex character
            return result;
        }

        // Convert second hex character
        if (hex_char2 >= '0' && hex_char2 <= '9') {
            val2 = hex_char2 - '0';
        } else if (hex_char2 >= 'a' && hex_char2 <= 'f') {
            val2 = hex_char2 - 'a' + 10;
        } else if (hex_char2 >= 'A' && hex_char2 <= 'F') {
            val2 = hex_char2 - 'A' + 10;
        } else {
            // Invalid hex character
            return result;
        }

        // Combine the two hex values into one byte
        unsigned char byte_val = (val1 << 4) | val2;
        result.push_back(byte_val);
    }

    return result;
}

