    switch (reason) {
        case AbortReason::WAKE_WORD_DETECTED:
            reason_str = "wake_word_detected";
            break;
        case AbortReason::USER_INTERRUPT:
            reason_str = "user_interrupt";
            break;
        case AbortReason::TIMEOUT:
