bool Protocol::IsTimeout() const
{
    // Check if time elapsed since last incoming message exceeds 120 seconds
    const auto now = std::chrono::steady_clock::now();
    const auto elapsed = std::chrono::duration_cast<std::chrono::seconds>(now - last_incoming_time_).count();

    if (elapsed > 120) {
        ESP_LOGE(TAG, "Audio channel timed out after %ld seconds", elapsed);
        return true;
    }

    return false;
}

bool WebsocketProtocol::Start()
{
    // Initialize WebSocket connection parameters
    const char* ws_url = "ws://your-server-address"; // This would typically come from settings

    // Create WebSocket client instance
    // Note: Actual WebSocket client creation would depend on the specific library being used
    // This is a placeholder for the actual initialization logic

    // Set up connection parameters
    esp_websocket_client_config_t websocket_cfg = {};
    websocket_cfg.uri = ws_url;
    websocket_cfg.event_handler = &WebsocketProtocol::websocket_event_handler;
    websocket_cfg.user_context = this;

    // Create WebSocket client
    websocket_client_ = esp_websocket_client_init(&websocket_cfg);

    // Connect to WebSocket server
    esp_err_t err = esp_websocket_client_start(websocket_client_);

    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to start WebSocket connection");
        return false;
    }

    // Wait for connection to be established
    EventBits_t bits = xEventGroupWaitBits(event_group_handle_, 
                                          WS_CONNECTED_BIT, 
                                          pdTRUE, 
                                          pdFALSE, 
                                          pdMS_TO_TICKS(5000));

    if (!(bits & WS_CONNECTED_BIT))
    {
        ESP_LOGE(TAG, "WebSocket connection timeout");
        esp_websocket_client_stop(websocket_client_);
        return false;
    }

    ESP_LOGI(TAG, "WebSocket connection started successfully");
    return true;
}

void WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    // Check if WebSocket connection is established
    if (!(xEventGroupGetBits(event_group_handle_) & WS_CONNECTED)) {
        ESP_LOGW(TAG, "WebSocket not connected, dropping audio packet");
        return;
    }

    // Validate packet
    if (!packet || !packet->data || packet->size == 0) {
        ESP_LOGW(TAG, "Invalid audio packet");
        return;
    }

    // Prepare websocket frame based on protocol version
    uint8_t* frame_data = nullptr;
    size_t frame_size = 0;

    // Determine protocol version from settings or negotiation
    int version = 0; // This would typically come from negotiated version

    // For demonstration, assuming we have access to version information
    // In real implementation, this might be retrieved from member variables
    if (version == 2 || version == 3) {
        // Binary protocol format (v2/v3)
        // Calculate total frame size including headers
        size_t header_size = 8; // Assuming 8-byte header for version 2/3
        frame_size = header_size + packet->size;

        frame_data = new uint8_t[frame_size];

        // Fill header with protocol version and timestamp
        uint32_t timestamp = esp_timer_get_time() / 1000; // milliseconds
        frame_data[0] = (version >> 24) & 0xFF;
        frame_data[1] = (version >> 16) & 0xFF;
        frame_data[2] = (version >> 8) & 0xFF;
        frame_data[3] = version & 0xFF;

        // Timestamp (4 bytes)
        frame_data[4] = (timestamp >> 24) & 0xFF;
        frame_data[5] = (timestamp >> 16) & 0xFF;
        frame_data[6] = (timestamp >> 8) & 0xFF;
        frame_data[7] = timestamp & 0xFF;

        // Copy audio data
        memcpy(frame_data + header_size, packet->data, packet->size);
    } else {
        // Raw payload format
        frame_size = packet->size;
        frame_data = new uint8_t[frame_size];
        memcpy(frame_data, packet->data, packet->size);
    }

    // Send via WebSocket (assuming there's a send method available)
    // This is a placeholder - actual implementation depends on WebSocket library used
    // bool sent = SendFrame(frame_data, frame_size, WEBSOCKET_BINARY_FRAME);

    // Clean up
    delete[] frame_data;
}

bool WebsocketProtocol::SendText(const std::string &text)
{
    // Check if WebSocket is connected
    if (!is_connected_) {
        ESP_LOGW(TAG, "WebSocket is not connected, cannot send text message");
        return false;
    }

    // Attempt to send the text message
    if (websocket_client_ != nullptr) {
        int result = esp_websocket_client_send_text(websocket_client_, text.c_str(), text.length(), 0);
        if (result < 0) {
            ESP_LOGE(TAG, "Failed to send text message over WebSocket: %d", result);

            // Set server error state
            if (event_group_handle_ != nullptr) {
                xEventGroupSetBits(event_group_handle_, SERVER_ERROR_BIT);
            }

            return false;
        }
    } else {
        ESP_LOGE(TAG, "WebSocket client is null, cannot send text message");
        return false;
    }

    return true;
}

bool WebsocketProtocol::OpenAudioChannel()
{
    // Create WebSocket client configuration
    esp_websocket_client_config_t websocket_cfg = {};

    // Set WebSocket URI (example - would need to be configured properly)
    websocket_cfg.uri = "ws://localhost:8080/audio"; // This should be configurable

    // Set authentication headers
    const char* auth_token = GetAuthToken(); // Assuming this method exists
    if (auth_token != nullptr) {
        websocket_cfg.headers = (char**)malloc(2 * sizeof(char*));
        websocket_cfg.headers[0] = (char*)malloc(256);
        snprintf(websocket_cfg.headers[0], 256, "Authorization: Bearer %s", auth_token);
        websocket_cfg.headers[1] = NULL;
        websocket_cfg.headers_count = 1;
    }

    // Set protocol version
    websocket_cfg.user_context = this;

    // Create WebSocket client
    websocket_client_ = esp_websocket_client_init(&websocket_cfg);

    // Check if client was created successfully
    if (websocket_client_ == NULL) {
        ESP_LOGE(TAG, "Failed to create WebSocket client");
        return false;
    }

    // Set up event handlers
    esp_websocket_client_set_event_callback(websocket_client_, websocket_event_handler, this);

    // Set up data handler for audio packets
    esp_websocket_client_set_data_handler(websocket_client_, audio_data_handler, this);

    // Connect to WebSocket server
    esp_err_t err = esp_websocket_client_start(websocket_client_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start WebSocket client: %s", esp_err_to_name(err));
        esp_websocket_client_destroy(websocket_client_);
        websocket_client_ = NULL;
        return false;
    }

    // Wait for connection establishment
    EventBits_t bits = xEventGroupWaitBits(event_group_handle_, 
                                          WEBSOCKET_CONNECTED_BIT, 
                                          pdTRUE, 
                                          pdFALSE, 
                                          pdMS_TO_TICKS(5000));

    if (!(bits & WEBSOCKET_CONNECTED_BIT)) {
        ESP_LOGE(TAG, "WebSocket connection timeout");
        esp_websocket_client_stop(websocket_client_);
        esp_websocket_client_destroy(websocket_client_);
        websocket_client_ = NULL;
        return false;
    }

    // Send audio channel open message with protocol version and device info
    cJSON *root = cJSON_CreateObject();
    if (root == NULL) {
        ESP_LOGE(TAG, "Failed to create JSON root object");
        return false;
    }

    // Add protocol version
    cJSON_AddNumberToObject(root, "version", 3); // Assuming v3 as default

    // Add device identifiers
    cJSON_AddStringToObject(root, "device_id", GetDeviceId()); // Assuming this method exists
    cJSON_AddStringToObject(root, "device_type", "audio_streamer"); // Assuming this method exists

    // Add authentication token
    if (auth_token != nullptr) {
        cJSON_AddStringToObject(root, "token", auth_token);
    }

    // Add frame duration if available
    if (server_frame_duration_ > 0) {
        cJSON_AddNumberToObject(root, "frame_duration", server_frame_duration_);
    }

    // Get JSON string
    char *json_string = cJSON_PrintUnformatted(root);
    if (json_string == NULL) {
        cJSON_Delete(root);
        ESP_LOGE(TAG, "Failed to print JSON");
        return false;
    }

    // Send JSON message to server
    err = esp_websocket_client_send_text(websocket_client_, json_string, strlen(json_string), 1000 / portTICK_PERIOD_MS);
    cJSON_Delete(root);
    free(json_string);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to send audio channel open message");
        return false;
    }

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

std::string WebsocketProtocol::GetHelloMessage()
{
    cJSON *root = cJSON_CreateObject();
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to create JSON root object");
        return "";
    }

    // Add protocol version
    cJSON_AddNumberToObject(root, "version", 1);

    // Add supported features
    cJSON *features = cJSON_CreateObject();
    if (features != nullptr) {
        cJSON_AddBoolToObject(features, "aec", true);   // AEC support
        cJSON_AddBoolToObject(features, "mcp", true);   // MCP support
        cJSON_AddItemToObject(root, "features", features);
    }

    // Add transport method
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add audio parameters
    cJSON *audio = cJSON_CreateObject();
    if (audio != nullptr) {
        cJSON_AddStringToObject(audio, "format", "pcm");           // Audio format
        cJSON_AddNumberToObject(audio, "sample_rate", 16000);     // Sample rate
        cJSON_AddNumberToObject(audio, "channels", 1);            // Channels
        cJSON_AddNumberToObject(audio, "frame_duration", 20);     // Frame duration in ms
        cJSON_AddItemToObject(root, "audio", audio);
    }

    // Add system information
    cJSON *system_info = cJSON_CreateObject();
    if (system_info != nullptr) {
        cJSON_AddStringToObject(system_info, "device_id", get_device_id());
        cJSON_AddStringToObject(system_info, "firmware_version", get_firmware_version());
        cJSON_AddStringToObject(system_info, "language", get_current_language());
        cJSON_AddItemToObject(root, "system", system_info);
    }

    // Generate JSON string
    char *json_string = cJSON_PrintUnformatted(root);
    std::string result = json_string ? json_string : "";

    // Clean up
    cJSON_Delete(root);
    if (json_string) {
        free(json_string);
    }

    return result;
}

bool WebsocketProtocol::ParseServerHello(const cJSON *json)
{
    // Check if JSON is valid
    if (json == nullptr) {
        ESP_LOGE(TAG, "Invalid JSON in server hello");
        return false;
    }

    // Extract session ID
    const cJSON *session_id = cJSON_GetObjectItem(json, "session_id");
    if (session_id != nullptr && cJSON_IsString(session_id)) {
        strncpy(session_id_, session_id->valuestring, sizeof(session_id_) - 1);
        session_id_[sizeof(session_id_) - 1] = '\0';
        ESP_LOGI(TAG, "Received session ID: %s", session_id_->valuestring);
    } else {
        ESP_LOGE(TAG, "Missing or invalid session_id in server hello");
        return false;
    }

    // Extract transport type
    const cJSON *transport = cJSON_GetObjectItem(json, "transport");
    if (transport != nullptr && cJSON_IsString(transport)) {
        if (strcmp(transport->valuestring, "websocket") != 0) {
            ESP_LOGE(TAG, "Unsupported transport type: %s", transport->valuestring);
            return false;
        }
    } else {
        ESP_LOGE(TAG, "Missing or invalid transport in server hello");
        return false;
    }

    // Extract audio configuration
    const cJSON *audio_config = cJSON_GetObjectItem(json, "audio_config");
    if (audio_config != nullptr) {
        // Extract sample rate
        const cJSON *sample_rate = cJSON_GetObjectItem(audio_config, "sample_rate");
        if (sample_rate != nullptr && cJSON_IsNumber(sample_rate)) {
            sample_rate_ = sample_rate->valueint;
            ESP_LOGI(TAG, "Audio sample rate: %d Hz", sample_rate_);
        }

        // Extract frame duration
        const cJSON *frame_duration = cJSON_GetObjectItem(audio_config, "frame_duration");
        if (frame_duration != nullptr && cJSON_IsNumber(frame_duration)) {
            frame_duration_ = frame_duration->valueint;
            ESP_LOGI(TAG, "Audio frame duration: %d ms", frame_duration_);
        }

        // Extract channels
        const cJSON *channels = cJSON_GetObjectItem(audio_config, "channels");
        if (channels != nullptr && cJSON_IsNumber(channels)) {
            channels_ = channels->valueint;
            ESP_LOGI(TAG, "Audio channels: %d", channels_);
        }
    }

    // Set event flag to indicate successful handshake
    xEventGroupSetBits(event_group_handle_, WS_EVENT_HANDSHAKE_COMPLETE);

    ESP_LOGI(TAG, "Server hello parsed successfully");
    return true;
}
